eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   TOPIC_LABELS: () => (/* binding */ TOPIC_LABELS),\n/* harmony export */   concepts: () => (/* binding */ concepts),\n/* harmony export */   getConceptById: () => (/* binding */ getConceptById)\n/* harmony export */ });\n/**\n * AWS Cloud Practitioner (CLF-C02) core concepts beyond individual services.\n * Source: AWS official docs + Stephane Maarek CLF-C02 PDF + AWS exam guide.\n */ const globalInfrastructure = [\n    {\n        id: \"regions\",\n        title: {\n            en: \"AWS Regions\",\n            ro: \"Regiuni AWS\"\n        },\n        tagline: {\n            en: \"Geographic clusters of data centers — independent and isolated.\",\n            ro: \"Clustere geografice de data centers — independente și izolate.\"\n        },\n        topic: \"global-infrastructure\",\n        aliases: [\n            \"region\",\n            \"regions\",\n            \"aws region\",\n            \"eu-west-1\",\n            \"us-east-1\",\n            \"data centers\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"What is a Region?\",\n                    ro: \"Ce este o Regiune?\"\n                },\n                body: {\n                    en: \"A Region is a separate geographic area in the world (e.g., us-east-1 in N. Virginia, eu-west-1 in Ireland). Each Region contains multiple, isolated, physically separate Availability Zones (AZs). As of 2024 there are 33 Regions and 105 Availability Zones globally.\",\n                    ro: \"O Regiune este o zonă geografică separată \\xeen lume (ex: us-east-1 \\xeen Virginia, eu-west-1 \\xeen Irlanda). Fiecare Regiune conține mai multe AZ-uri (Availability Zones) izolate fizic. La 2024 sunt 33 de Regiuni și 105 AZ-uri global.\"\n                }\n            },\n            {\n                heading: {\n                    en: \"How to choose a Region\",\n                    ro: \"Cum alegi o Regiune\"\n                },\n                body: {\n                    en: \"- Compliance: data sovereignty laws (e.g., GDPR requires EU regions)\\n- Latency: closer to users = faster\\n- Available services: not every service is in every Region\\n- Pricing: prices vary per Region (us-east-1 is usually cheapest)\",\n                    ro: \"- Compliance: legi de suveranitate date (GDPR cere regiuni EU)\\n- Latență: mai aproape de utilizatori = mai rapid\\n- Servicii disponibile: nu fiecare serviciu există \\xeen fiecare Regiune\\n- Preț: variază pe Regiune (us-east-1 e de obicei cel mai ieftin)\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Region scope of services\",\n                    ro: \"Scope-ul regional al serviciilor\"\n                },\n                body: {\n                    en: \"- Region-scoped: most services (EC2, RDS, S3 buckets, Lambda)\\n- Global: IAM, Route 53, CloudFront, WAF, Organizations\\n- AZ-scoped: EBS volumes, EC2 instances live in a specific AZ\",\n                    ro: \"- Regional: majoritatea (EC2, RDS, S3 buckets, Lambda)\\n- Global: IAM, Route 53, CloudFront, WAF, Organizations\\n- Per-AZ: volumele EBS, instanțele EC2 sunt \\xeentr-un AZ specific\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"33 Regions worldwide (2024).\",\n                ro: \"33 de Regiuni global (2024).\"\n            },\n            {\n                en: \"Each Region is fully isolated from the others (no automatic data replication).\",\n                ro: \"Fiecare Regiune e complet izolată (fără replicare automată).\"\n            },\n            {\n                en: \"Region code format: 2-letter geo + direction + number (e.g., eu-central-1).\",\n                ro: \"Format cod regiune: 2 litere geo + direcție + număr (ex: eu-central-1).\"\n            },\n            {\n                en: \"Always check service availability before choosing a Region.\",\n                ro: \"Verifică mereu disponibilitatea serviciilor \\xeenainte să alegi.\"\n            }\n        ],\n        relatedConcepts: [\n            \"availability-zones\",\n            \"edge-locations\",\n            \"local-zones\"\n        ],\n        relatedServices: [\n            \"ec2\",\n            \"s3\",\n            \"route53\"\n        ],\n        docsUrl: \"https://aws.amazon.com/about-aws/global-infrastructure/regions_az/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"availability-zones\",\n        title: {\n            en: \"Availability Zones (AZ)\",\n            ro: \"Availability Zones (AZ)\"\n        },\n        tagline: {\n            en: \"Isolated data centers within a Region — for high availability.\",\n            ro: \"Data centers izolate \\xeen interiorul unei Regiuni — pentru HA.\"\n        },\n        topic: \"global-infrastructure\",\n        aliases: [\n            \"az\",\n            \"azs\",\n            \"availability zone\",\n            \"data center\",\n            \"multi-az\",\n            \"multi az\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"What is an AZ?\",\n                    ro: \"Ce este un AZ?\"\n                },\n                body: {\n                    en: \"An Availability Zone is one or more discrete data centers within a Region, each with redundant power, networking, and connectivity. AZs in a Region are physically separated by meaningful distance (km apart) but interconnected with low-latency, high-throughput, redundant private fiber.\",\n                    ro: \"Un Availability Zone reprezintă unul sau mai multe data centers discrete dintr-o Regiune, fiecare cu alimentare, rețea și conectivitate redundante. AZ-urile din aceeași Regiune sunt separate fizic la distanță semnificativă (km), dar conectate cu fibră privată redundantă, de mare debit, latență mică.\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Why multiple AZs?\",\n                    ro: \"De ce mai multe AZ-uri?\"\n                },\n                body: {\n                    en: \"- Fault isolation: if one AZ goes down (fire, flood, power outage), others keep running\\n- High Availability (HA) architectures need at least 2 AZs\\n- Multi-AZ RDS, EC2 Auto Scaling, ELB target groups all use AZs\",\n                    ro: \"- Izolare pe defecte: dacă un AZ cade (incendiu, inundație, oprire curent), restul merg\\n- Arhitecturi High Availability (HA) au nevoie de minim 2 AZ-uri\\n- Multi-AZ RDS, EC2 Auto Scaling, target groups ELB folosesc AZ-uri\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Numbers to remember\",\n                    ro: \"Numere de reținut\"\n                },\n                body: {\n                    en: \"- Each Region has 3+ AZs (most have 3, some up to 6)\\n- 105 total AZs globally (2024)\\n- AZ code: Region + letter (e.g., eu-west-1a, eu-west-1b, eu-west-1c)\\n- Each AZ contains 1+ physical data centers\",\n                    ro: \"- Fiecare Regiune are 3+ AZ-uri (majoritatea 3, unele p\\xe2nă la 6)\\n- 105 AZ-uri total global (2024)\\n- Cod AZ: Regiune + literă (eu-west-1a, eu-west-1b, eu-west-1c)\\n- Fiecare AZ conține 1+ data centers fizice\"\n                }\n            },\n            {\n                heading: {\n                    en: \"AZ vs Region in practice\",\n                    ro: \"AZ vs Regiune \\xeen practică\"\n                },\n                body: {\n                    en: \"Multi-AZ = inside ONE Region, redundancy across data centers (synchronous, low latency). Multi-Region = redundancy across geographic regions (asynchronous, used for disaster recovery and global apps).\",\n                    ro: \"Multi-AZ = \\xeen AceeAȘI Regiune, redundanță \\xeentre data centers (sincron, latență mică). Multi-Region = redundanță \\xeentre regiuni geografice (asincron, pentru disaster recovery și aplicații globale).\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Each Region has at least 3 Availability Zones.\",\n                ro: \"Fiecare Regiune are minim 3 AZ-uri.\"\n            },\n            {\n                en: \"105 AZs globally as of 2024.\",\n                ro: \"105 AZ-uri global la 2024.\"\n            },\n            {\n                en: \"AZs are physically separate but connected with low-latency fiber.\",\n                ro: \"AZ-urile sunt fizic separate dar conectate prin fibră cu latență mică.\"\n            },\n            {\n                en: \"For HA you need to deploy across at least 2 AZs.\",\n                ro: \"Pentru HA trebuie să faci deploy peste minim 2 AZ-uri.\"\n            },\n            {\n                en: \"EC2 instances and EBS volumes live in ONE specific AZ.\",\n                ro: \"Instanțele EC2 și volumele EBS sunt \\xeentr-un AZ specific.\"\n            },\n            {\n                en: \"EFS works across AZs; EBS does not.\",\n                ro: \"EFS funcționează cross-AZ; EBS nu.\"\n            }\n        ],\n        relatedConcepts: [\n            \"regions\",\n            \"edge-locations\"\n        ],\n        relatedServices: [\n            \"ec2\",\n            \"ebs\",\n            \"rds\",\n            \"elb\",\n            \"efs\"\n        ],\n        docsUrl: \"https://aws.amazon.com/about-aws/global-infrastructure/regions_az/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"edge-locations\",\n        title: {\n            en: \"Edge Locations\",\n            ro: \"Edge Locations\"\n        },\n        tagline: {\n            en: \"Hundreds of points of presence (PoPs) used by CloudFront and Route 53.\",\n            ro: \"Sute de puncte de prezență (PoPs) folosite de CloudFront și Route 53.\"\n        },\n        topic: \"global-infrastructure\",\n        aliases: [\n            \"edge\",\n            \"pop\",\n            \"point of presence\",\n            \"cdn\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"What are Edge Locations?\",\n                    ro: \"Ce sunt Edge Locations?\"\n                },\n                body: {\n                    en: \"Edge Locations are smaller AWS facilities deployed in metropolitan areas worldwide that cache content closer to users. They are NOT full Regions or AZs — they only host a subset of services (mainly CloudFront, Route 53, AWS Shield, AWS WAF, Lambda@Edge).\",\n                    ro: \"Edge Locations sunt facilități AWS mai mici, deployate \\xeen zone metropolitane global, care cache conținut mai aproape de utilizatori. NU sunt Regiuni sau AZ-uri — găzduiesc doar un subset de servicii (mai ales CloudFront, Route 53, Shield, WAF, Lambda@Edge).\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Numbers\",\n                    ro: \"Numere\"\n                },\n                body: {\n                    en: \"- 450+ Edge Locations across 90+ cities in 40+ countries\\n- 13+ Regional Edge Caches (intermediate cache between Edges and origins)\",\n                    ro: \"- 450+ Edge Locations \\xeen 90+ orașe din 40+ țări\\n- 13+ Regional Edge Caches (cache intermediar \\xeentre Edges și originile)\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"450+ Edge Locations globally.\",\n                ro: \"450+ Edge Locations global.\"\n            },\n            {\n                en: \"Used primarily by CloudFront (CDN) to cache content closer to users.\",\n                ro: \"Folosite \\xeen principal de CloudFront (CDN) pentru cache aproape de utilizatori.\"\n            },\n            {\n                en: \"Edge Locations are NOT full data centers; they cache only.\",\n                ro: \"Edge Locations NU sunt data centers complete; doar fac cache.\"\n            }\n        ],\n        relatedConcepts: [\n            \"regions\",\n            \"availability-zones\"\n        ],\n        relatedServices: [\n            \"cloudfront\",\n            \"route53\",\n            \"shield\",\n            \"waf\"\n        ],\n        docsUrl: \"https://aws.amazon.com/about-aws/global-infrastructure/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"local-zones\",\n        title: {\n            en: \"Local Zones, Wavelength & Outposts\",\n            ro: \"Local Zones, Wavelength & Outposts\"\n        },\n        tagline: {\n            en: \"Bring AWS closer to users — on-premises, 5G networks, or specific cities.\",\n            ro: \"Aduci AWS aproape de utilizatori — on-premises, rețele 5G sau orașe specifice.\"\n        },\n        topic: \"global-infrastructure\",\n        aliases: [\n            \"local zone\",\n            \"wavelength\",\n            \"outpost\",\n            \"5g\",\n            \"on-premises\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"AWS Local Zones\",\n                    ro: \"AWS Local Zones\"\n                },\n                body: {\n                    en: \"Mini-Regions deployed in major metropolitan areas (e.g., Los Angeles, Las Vegas, Houston) for ultra-low latency to end users. Useful for media/entertainment, gaming, real-time apps. Connected to a parent Region.\",\n                    ro: \"Mini-Regiuni deployate \\xeen zone metropolitane mari (Los Angeles, Las Vegas, Houston) pentru latență ultra-mică la utilizatori. Utile pentru media, gaming, aplicații real-time. Conectate la o Regiune părinte.\"\n                }\n            },\n            {\n                heading: {\n                    en: \"AWS Wavelength\",\n                    ro: \"AWS Wavelength\"\n                },\n                body: {\n                    en: \"AWS infrastructure embedded in 5G telecom networks (Verizon, KDDI, Vodafone). Provides single-digit millisecond latency for mobile apps — gaming, AR/VR, ML inference at the edge.\",\n                    ro: \"Infrastructură AWS \\xeen rețele 5G ale operatorilor (Verizon, KDDI, Vodafone). Latență sub 10ms pentru aplicații mobile — gaming, AR/VR, ML inference la edge.\"\n                }\n            },\n            {\n                heading: {\n                    en: \"AWS Outposts\",\n                    ro: \"AWS Outposts\"\n                },\n                body: {\n                    en: \"Physical racks of AWS hardware delivered to YOUR data center. You run AWS services on-premises with the same APIs and tools. Use cases: low-latency local processing, data residency, or hybrid migration in progress.\",\n                    ro: \"Rack-uri fizice AWS livrate \\xeen data center-ul TĂU. Rulezi servicii AWS on-premises cu aceleași API-uri. Cazuri: procesare locală cu latență mică, data residency, migrare hibridă.\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Local Zones: AWS closer to specific metropolitan areas.\",\n                ro: \"Local Zones: AWS aproape de zone metropolitane specifice.\"\n            },\n            {\n                en: \"Wavelength: AWS embedded in 5G carrier networks.\",\n                ro: \"Wavelength: AWS integrat \\xeen rețele 5G.\"\n            },\n            {\n                en: \"Outposts: AWS hardware racks running ON YOUR site.\",\n                ro: \"Outposts: rack-uri AWS rul\\xe2nd LA TINE pe site.\"\n            }\n        ],\n        relatedConcepts: [\n            \"regions\",\n            \"availability-zones\"\n        ],\n        relatedServices: [\n            \"outposts\",\n            \"ec2\"\n        ],\n        docsUrl: \"https://aws.amazon.com/about-aws/global-infrastructure/localzones/\",\n        examFrequency: \"medium\"\n    }\n];\nconst sharedResponsibility = [\n    {\n        id: \"shared-responsibility\",\n        title: {\n            en: \"Shared Responsibility Model\",\n            ro: \"Modelul Responsabilității Partajate\"\n        },\n        tagline: {\n            en: \"AWS secures the cloud; you secure what you put IN the cloud.\",\n            ro: \"AWS securizează cloud-ul; tu securizezi ce pui \\xceN cloud.\"\n        },\n        topic: \"shared-responsibility\",\n        aliases: [\n            \"shared responsibility\",\n            \"security\",\n            \"who is responsible\",\n            \"compliance\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"AWS responsibility — Security OF the cloud\",\n                    ro: \"Responsabilitatea AWS — Securitatea CLOUD-ului\"\n                },\n                body: {\n                    en: \"- Physical hardware, data centers, regions, AZs, edge locations\\n- Network infrastructure (cabling, switches, firewalls)\\n- Hypervisor that runs your virtual machines\\n- Managed service software (RDS database engine, S3 storage subsystem)\\n- Patching of underlying infrastructure\",\n                    ro: \"- Hardware fizic, data centers, regiuni, AZ-uri, edge locations\\n- Infrastructura de rețea (cabluri, switch-uri, firewall-uri)\\n- Hipervizorul care rulează VM-urile tale\\n- Software-ul serviciilor managed (motorul DB RDS, subsystem-ul S3)\\n- Patching infrastructură subiacentă\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Your responsibility — Security IN the cloud\",\n                    ro: \"Responsabilitatea ta — Securitatea \\xceN cloud\"\n                },\n                body: {\n                    en: \"- Customer data (encryption, classification)\\n- IAM users, groups, roles, policies\\n- OS patching for EC2 (NOT for managed services)\\n- Application code, network/firewall config (Security Groups, NACLs)\\n- Client-side encryption keys\\n- Updating server-side encryption settings\",\n                    ro: \"- Date utilizator (criptare, clasificare)\\n- Useri, grupuri, roluri, politici IAM\\n- Patching OS pentru EC2 (NU pentru servicii managed)\\n- Cod aplicație, config rețea/firewall (Security Groups, NACLs)\\n- Chei de criptare client-side\\n- Setări criptare server-side\"\n                }\n            },\n            {\n                heading: {\n                    en: \"How it shifts by service\",\n                    ro: \"Cum se schimbă pe servicii\"\n                },\n                body: {\n                    en: \"- IaaS (EC2): YOU patch OS, install software, manage firewall. AWS only handles hardware.\\n- PaaS (RDS, ECS): AWS patches OS and DB engine. YOU manage data and access.\\n- SaaS (S3, DynamoDB): AWS handles almost everything. YOU only manage data and access policies.\",\n                    ro: \"- IaaS (EC2): TU faci patch la OS, instalezi software, firewall. AWS doar hardware.\\n- PaaS (RDS, ECS): AWS patches OS și motor DB. TU date și acces.\\n- SaaS (S3, DynamoDB): AWS face aproape tot. TU doar date și politici acces.\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"AWS = Security OF the cloud.\",\n                ro: \"AWS = Securitatea CLOUD-ului.\"\n            },\n            {\n                en: \"Customer = Security IN the cloud.\",\n                ro: \"Customer = Securitatea \\xceN cloud.\"\n            },\n            {\n                en: \"Patching: AWS for managed services, customer for EC2 OS.\",\n                ro: \"Patching: AWS pentru servicii managed, clientul pentru OS-ul EC2.\"\n            },\n            {\n                en: \"IAM is ALWAYS your responsibility.\",\n                ro: \"IAM este MEREU responsabilitatea ta.\"\n            },\n            {\n                en: \"Encryption keys: KMS keys can be managed by AWS or by you (CMK).\",\n                ro: \"Chei de criptare: KMS poate fi managed de AWS sau de tine (CMK).\"\n            }\n        ],\n        relatedConcepts: [\n            \"well-architected\",\n            \"iam-best-practices\"\n        ],\n        relatedServices: [\n            \"iam\",\n            \"kms\",\n            \"cloudtrail\"\n        ],\n        docsUrl: \"https://aws.amazon.com/compliance/shared-responsibility-model/\",\n        examFrequency: \"high\"\n    }\n];\nconst wellArchitected = [\n    {\n        id: \"well-architected\",\n        title: {\n            en: \"Well-Architected Framework (6 Pillars)\",\n            ro: \"Well-Architected Framework (6 piloni)\"\n        },\n        tagline: {\n            en: \"AWS best-practice framework for building secure, reliable, efficient systems.\",\n            ro: \"Framework de best-practices AWS pentru sisteme sigure, reliable, eficiente.\"\n        },\n        topic: \"well-architected\",\n        aliases: [\n            \"well architected\",\n            \"pillars\",\n            \"best practices\",\n            \"framework\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"The 6 Pillars\",\n                    ro: \"Cei 6 piloni\"\n                },\n                body: {\n                    en: \"1. Operational Excellence — run/monitor systems, continually improve processes\\n2. Security — protect data, systems, identities (encryption, IAM, audit)\\n3. Reliability — recover from failure, dynamically scale, automate recovery\\n4. Performance Efficiency — use compute resources optimally as demand changes\\n5. Cost Optimization — avoid unnecessary cost; right-sizing, RIs, Spot\\n6. Sustainability — reduce environmental impact (added in 2021)\",\n                    ro: \"1. Operational Excellence — rulezi/monitorizezi sisteme, \\xeembunătățești procese\\n2. Security — protejezi date, sisteme, identități (criptare, IAM, audit)\\n3. Reliability — recovery din defect, scalare dinamică, recuperare automată\\n4. Performance Efficiency — folosești resurse optim c\\xe2nd cererea se schimbă\\n5. Cost Optimization — eviți costuri inutile; right-sizing, RI, Spot\\n6. Sustainability — reducerea impactului ecologic (adăugat \\xeen 2021)\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Well-Architected Tool\",\n                    ro: \"Well-Architected Tool\"\n                },\n                body: {\n                    en: \"Free tool in the AWS Console that lets you review your workload against the 6 pillars by answering questions. It produces a list of high/medium/low risk issues with documented best-practice remediations.\",\n                    ro: \"Tool gratuit \\xeen consola AWS care \\xeeți permite să verifici workload-ul după cei 6 piloni răspunz\\xe2nd la \\xeentrebări. Produce o listă de probleme high/medium/low cu remedieri documentate.\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"6 pillars: Operational Excellence, Security, Reliability, Performance, Cost, Sustainability.\",\n                ro: \"6 piloni: Operational Excellence, Security, Reliability, Performance, Cost, Sustainability.\"\n            },\n            {\n                en: \"Sustainability was added as the 6th pillar in late 2021.\",\n                ro: \"Sustainability a fost adăugat al 6-lea pilon \\xeen 2021.\"\n            },\n            {\n                en: \"Well-Architected Tool is free.\",\n                ro: \"Well-Architected Tool e gratuit.\"\n            }\n        ],\n        relatedConcepts: [\n            \"shared-responsibility\",\n            \"cloud-advantages\"\n        ],\n        docsUrl: \"https://aws.amazon.com/architecture/well-architected/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"design-principles\",\n        title: {\n            en: \"Cloud Design Principles\",\n            ro: \"Principii de Design Cloud\"\n        },\n        tagline: {\n            en: \"Stop treating servers as pets — make them cattle.\",\n            ro: \"Nu mai trata serverele ca pe animale de companie — fă-le turmă.\"\n        },\n        topic: \"well-architected\",\n        aliases: [\n            \"design principles\",\n            \"cloud principles\",\n            \"pets cattle\",\n            \"immutable\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"Key principles\",\n                    ro: \"Principii cheie\"\n                },\n                body: {\n                    en: \"- Stop guessing capacity (auto-scale instead)\\n- Test at production scale (cloud lets you spin up huge envs)\\n- Automate everything (Infrastructure-as-Code with CloudFormation)\\n- Use evolutionary architectures (refactor easily)\\n- Drive architecture using data (CloudWatch metrics)\\n- Practice game days (test failure scenarios in production)\",\n                    ro: \"- Nu mai ghici capacitatea (folosește auto-scale)\\n- Testează la scară producție (cloud \\xeeți permite environments uriașe)\\n- Automatizezi tot (Infrastructure-as-Code cu CloudFormation)\\n- Folosește arhitecturi evolutive (refactor ușor)\\n- Bazează arhitectura pe date (metrici CloudWatch)\\n- Game days (testezi scenarii de defect \\xeen producție)\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Auto-scaling replaces capacity guessing.\",\n                ro: \"Auto-scaling \\xeenlocuiește ghicirea capacității.\"\n            },\n            {\n                en: \"IaC (CloudFormation) enables repeatable infrastructure.\",\n                ro: \"IaC (CloudFormation) permite infrastructură repetabilă.\"\n            }\n        ],\n        relatedConcepts: [\n            \"well-architected\",\n            \"cloud-advantages\"\n        ],\n        examFrequency: \"medium\"\n    }\n];\nconst cloudFundamentals = [\n    {\n        id: \"cloud-advantages\",\n        title: {\n            en: \"6 Advantages of Cloud Computing\",\n            ro: \"6 Avantaje Cloud Computing\"\n        },\n        tagline: {\n            en: \"Why companies move from on-premises to AWS — the canonical six.\",\n            ro: \"De ce companii migrează de la on-premises la AWS — cele șase canonice.\"\n        },\n        topic: \"cloud-fundamentals\",\n        aliases: [\n            \"advantages\",\n            \"benefits\",\n            \"why cloud\",\n            \"capex opex\",\n            \"6 advantages\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"The six advantages\",\n                    ro: \"Cele șase avantaje\"\n                },\n                body: {\n                    en: \"1. Trade CAPEX for OPEX (variable expenses, no big upfront)\\n2. Massive economies of scale (AWS pays less, you pay less)\\n3. Stop guessing capacity (scale up/down on demand)\\n4. Increase speed and agility (resources in minutes, not weeks)\\n5. Stop spending money running data centers (focus on your customers)\\n6. Go global in minutes (deploy to multiple Regions easily)\",\n                    ro: \"1. CAPEX → OPEX (cheltuieli variabile, fără investiție mare upfront)\\n2. Economii de scară masive (AWS plătește mai puțin, tu la fel)\\n3. Nu mai ghici capacitatea (scalezi pe cerere)\\n4. Viteză și agilitate (resurse \\xeen minute, nu săptăm\\xe2ni)\\n5. Nu mai cheltui bani pe data centers (focus pe clienți)\\n6. Globalizare \\xeen minute (deploy \\xeen multe Regiuni ușor)\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"CAPEX = Capital Expenditure (upfront), OPEX = Operational (pay-as-you-go).\",\n                ro: \"CAPEX = investiție inițială, OPEX = pay-as-you-go.\"\n            },\n            {\n                en: \"Cloud removes data center management overhead.\",\n                ro: \"Cloud elimină overhead-ul managementului data center-ului.\"\n            }\n        ],\n        docsUrl: \"https://aws.amazon.com/what-is-cloud-computing/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"cloud-types\",\n        title: {\n            en: \"Types of Cloud Deployment\",\n            ro: \"Tipuri de Deployment Cloud\"\n        },\n        tagline: {\n            en: \"Public vs Private vs Hybrid — when to use which.\",\n            ro: \"Public vs Privat vs Hibrid — c\\xe2nd folosești fiecare.\"\n        },\n        topic: \"cloud-fundamentals\",\n        aliases: [\n            \"public cloud\",\n            \"private cloud\",\n            \"hybrid cloud\",\n            \"multi cloud\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"The three deployment models\",\n                    ro: \"Cele trei modele de deployment\"\n                },\n                body: {\n                    en: \"- Public Cloud: shared infrastructure (AWS, Azure, GCP) — pay only for use\\n- Private Cloud: dedicated infrastructure for one organization (on-premises or hosted)\\n- Hybrid Cloud: combination — some workloads on AWS, some on-premises (use AWS Outposts, Direct Connect, Storage Gateway)\",\n                    ro: \"- Public Cloud: infrastructură partajată (AWS, Azure, GCP) — plătești c\\xe2t folosești\\n- Private Cloud: infrastructură dedicată unei organizații (on-prem sau hosted)\\n- Hybrid Cloud: combinație — workloads pe AWS, altele on-premises (folosește Outposts, Direct Connect, Storage Gateway)\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Service models (IaaS / PaaS / SaaS)\",\n                    ro: \"Modele de serviciu (IaaS / PaaS / SaaS)\"\n                },\n                body: {\n                    en: \"- IaaS (Infrastructure-as-a-Service): EC2, EBS — you manage OS+\\n- PaaS (Platform-as-a-Service): Beanstalk, RDS — you manage code+data\\n- SaaS (Software-as-a-Service): WorkMail, Connect — you only use it\",\n                    ro: \"- IaaS: EC2, EBS — gestionezi de la OS \\xeen sus\\n- PaaS: Beanstalk, RDS — gestionezi cod și date\\n- SaaS: WorkMail, Connect — doar \\xeel folosești\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Hybrid = mix on-prem + cloud (AWS Outposts is a hybrid tool).\",\n                ro: \"Hybrid = mix on-prem + cloud (Outposts e tool hibrid).\"\n            },\n            {\n                en: \"IaaS gives most control; SaaS gives least.\",\n                ro: \"IaaS dă cel mai mult control; SaaS cel mai puțin.\"\n            }\n        ],\n        relatedConcepts: [\n            \"cloud-advantages\",\n            \"shared-responsibility\"\n        ],\n        examFrequency: \"medium\"\n    }\n];\nconst pricing = [\n    {\n        id: \"pricing-fundamentals\",\n        title: {\n            en: \"AWS Pricing Fundamentals\",\n            ro: \"Fundamentele Prețurilor AWS\"\n        },\n        tagline: {\n            en: \"Pay as you go, pay less when you reserve, pay even less for volume.\",\n            ro: \"Plătești c\\xe2t folosești, mai puțin c\\xe2nd rezervi, și mai puțin la volum.\"\n        },\n        topic: \"pricing\",\n        aliases: [\n            \"pricing\",\n            \"cost\",\n            \"billing\",\n            \"free tier\",\n            \"pay as you go\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"3 core pricing principles\",\n                    ro: \"3 principii de bază\"\n                },\n                body: {\n                    en: \"1. Pay-as-you-go: pay only for what you use, no long-term commitment\\n2. Pay less by reserving: discounts of 30-72% for 1-3 year commitments (RIs, Savings Plans)\\n3. Pay less per unit by using more: tiered pricing (S3 cheaper for 50TB+ than 5TB)\",\n                    ro: \"1. Pay-as-you-go: plătești doar ce folosești, fără angajament\\n2. Plătești mai puțin rezerv\\xe2nd: discount 30-72% la 1-3 ani angajament (RIs, Savings Plans)\\n3. Mai puțin pe unitate c\\xe2nd folosești mult: tiered pricing (S3 mai ieftin la 50TB+ vs 5TB)\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Free Tier\",\n                    ro: \"Free Tier\"\n                },\n                body: {\n                    en: \"- Always Free: e.g., DynamoDB 25GB, Lambda 1M req/month, CloudWatch 10 metrics\\n- 12-month Free: e.g., EC2 t2.micro 750h/month, S3 5GB, RDS db.t2.micro 750h\\n- Trials: short-term free trials for some services\",\n                    ro: \"- Always Free: ex DynamoDB 25GB, Lambda 1M req/lună, CloudWatch 10 metrici\\n- 12-luni Free: ex EC2 t2.micro 750h/lună, S3 5GB, RDS db.t2.micro 750h\\n- Trials: probe gratuite pe termen scurt pentru anumite servicii\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Things that are FREE in AWS\",\n                    ro: \"Ce este GRATUIT \\xeen AWS\"\n                },\n                body: {\n                    en: \"- IAM, VPC, Auto Scaling, CloudFormation, Elastic Beanstalk\\n- Inbound data transfer to AWS (from internet) is free\\n- Data transfer between services in same Region is mostly free or cheap\\n- Outbound data transfer is what costs money\",\n                    ro: \"- IAM, VPC, Auto Scaling, CloudFormation, Elastic Beanstalk\\n- Trafic INBOUND la AWS (de pe internet) e gratuit\\n- Trafic \\xeentre servicii \\xeen aceeași Regiune mostly gratuit sau ieftin\\n- Trafic OUTBOUND costă\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Pay-as-you-go = no upfront, no commitment.\",\n                ro: \"Pay-as-you-go = fără investiție inițială, fără angajament.\"\n            },\n            {\n                en: \"Reserved Instances and Savings Plans give 30-72% discount.\",\n                ro: \"Reserved Instances și Savings Plans dau 30-72% reducere.\"\n            },\n            {\n                en: \"Spot Instances give up to 90% discount but can be terminated with 2-min notice.\",\n                ro: \"Spot Instances dau p\\xe2nă la 90% reducere dar pot fi oprite cu 2-min preaviz.\"\n            },\n            {\n                en: \"Inbound data transfer is FREE; outbound is paid.\",\n                ro: \"Traficul inbound e GRATUIT; outbound se plătește.\"\n            },\n            {\n                en: \"IAM, VPC, CloudFormation, Auto Scaling are free.\",\n                ro: \"IAM, VPC, CloudFormation, Auto Scaling sunt gratuite.\"\n            }\n        ],\n        relatedConcepts: [\n            \"support-plans\"\n        ],\n        relatedServices: [\n            \"costexplorer\",\n            \"budgets\",\n            \"calculator\"\n        ],\n        docsUrl: \"https://aws.amazon.com/pricing/\",\n        examFrequency: \"high\"\n    },\n    {\n        id: \"support-plans\",\n        title: {\n            en: \"AWS Support Plans (4 tiers)\",\n            ro: \"Planuri de Suport AWS (4 nivele)\"\n        },\n        tagline: {\n            en: \"From free docs to dedicated 24/7 Technical Account Manager.\",\n            ro: \"De la docs gratuite la Technical Account Manager dedicat 24/7.\"\n        },\n        topic: \"support\",\n        aliases: [\n            \"support\",\n            \"support plans\",\n            \"tam\",\n            \"enterprise support\",\n            \"business support\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"The 5 plans\",\n                    ro: \"Cele 5 planuri\"\n                },\n                body: {\n                    en: \"- Basic: FREE — docs, whitepapers, forums, Personal Health Dashboard, 7 Trusted Advisor checks\\n- Developer: $29/month — email support, business-hours, 12-24h response\\n- Business: $100/month — 24/7 phone/chat, 1h response for prod issues, full Trusted Advisor\\n- Enterprise On-Ramp: $5,500/month — pool of TAMs, 30min response for business-critical\\n- Enterprise: $15,000/month — DEDICATED TAM, 15min response, Concierge for billing\",\n                    ro: \"- Basic: GRATUIT — docs, whitepapers, forumuri, Personal Health Dashboard, 7 Trusted Advisor checks\\n- Developer: $29/lună — suport email, business-hours, 12-24h răspuns\\n- Business: $100/lună — 24/7 telefon/chat, 1h răspuns la probleme prod, Trusted Advisor complet\\n- Enterprise On-Ramp: $5,500/lună — pool de TAM, 30min răspuns la business-critical\\n- Enterprise: $15,000/lună — TAM DEDICAT, 15min răspuns, Concierge pentru facturare\"\n                }\n            },\n            {\n                heading: {\n                    en: \"Who is a TAM?\",\n                    ro: \"Ce este un TAM?\"\n                },\n                body: {\n                    en: \"Technical Account Manager — your personal AWS architect who knows your environment. Available only on Enterprise On-Ramp (shared) and Enterprise (dedicated). They proactively review architecture, optimize costs, and help with major events.\",\n                    ro: \"Technical Account Manager — arhitectul tău personal AWS care \\xeeți cunoaște mediul. Disponibil doar la Enterprise On-Ramp (shared) și Enterprise (dedicat). Reviziuesc proactiv arhitectura, optimizează costuri, ajută la evenimente majore.\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Basic and Developer: NO 24/7 support.\",\n                ro: \"Basic și Developer: FĂRĂ suport 24/7.\"\n            },\n            {\n                en: \"Business: 24/7 phone, 1h response time for production down.\",\n                ro: \"Business: 24/7 telefon, 1h răspuns la prod down.\"\n            },\n            {\n                en: \"Enterprise: dedicated TAM + 15min response.\",\n                ro: \"Enterprise: TAM dedicat + 15min răspuns.\"\n            },\n            {\n                en: \"TAMs are only on Enterprise plans.\",\n                ro: \"TAM-urile sunt doar pe planurile Enterprise.\"\n            },\n            {\n                en: \"Concierge (billing assistance) is Enterprise-only.\",\n                ro: \"Concierge (asistență facturare) e doar Enterprise.\"\n            }\n        ],\n        relatedConcepts: [\n            \"pricing-fundamentals\"\n        ],\n        relatedServices: [\n            \"supportplans\",\n            \"trustedadvisor\"\n        ],\n        docsUrl: \"https://aws.amazon.com/premiumsupport/plans/\",\n        examFrequency: \"high\"\n    }\n];\nconst compliance = [\n    {\n        id: \"compliance-programs\",\n        title: {\n            en: \"AWS Compliance & Security Programs\",\n            ro: \"Programe Compliance & Securitate AWS\"\n        },\n        tagline: {\n            en: \"AWS holds dozens of certifications — find them in AWS Artifact.\",\n            ro: \"AWS deține zeci de certificări — le găsești \\xeen AWS Artifact.\"\n        },\n        topic: \"compliance\",\n        aliases: [\n            \"compliance\",\n            \"gdpr\",\n            \"hipaa\",\n            \"pci\",\n            \"soc\",\n            \"iso\",\n            \"artifact\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"Common certifications\",\n                    ro: \"Certificări comune\"\n                },\n                body: {\n                    en: \"- SOC 1, 2, 3 (auditing standards)\\n- ISO 27001, 27017, 27018 (information security)\\n- PCI DSS Level 1 (payment cards)\\n- HIPAA (US healthcare)\\n- GDPR (EU privacy)\\n- FedRAMP (US federal government)\\n- DoD SRG, FIPS 140-2\",\n                    ro: \"- SOC 1, 2, 3 (audit)\\n- ISO 27001, 27017, 27018 (securitate informatică)\\n- PCI DSS Level 1 (carduri plată)\\n- HIPAA (sănătate SUA)\\n- GDPR (privacy UE)\\n- FedRAMP (guvern federal SUA)\\n- DoD SRG, FIPS 140-2\"\n                }\n            },\n            {\n                heading: {\n                    en: \"AWS Artifact\",\n                    ro: \"AWS Artifact\"\n                },\n                body: {\n                    en: \"Self-service portal in the AWS Console where you download AWS compliance reports (SOC, PCI, ISO certificates) — used to give to your auditors. FREE service.\",\n                    ro: \"Portal self-service \\xeen consola AWS de unde descarci rapoarte de compliance AWS (certificate SOC, PCI, ISO) — pe care le dai auditorilor. Serviciu GRATUIT.\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"AWS Artifact is the place to download compliance reports.\",\n                ro: \"AWS Artifact e locul de unde descarci rapoarte compliance.\"\n            },\n            {\n                en: \"AWS holds over 90 certifications worldwide.\",\n                ro: \"AWS deține peste 90 de certificări global.\"\n            },\n            {\n                en: \"Compliance is shared: AWS certifies infrastructure; YOU must use it correctly.\",\n                ro: \"Compliance e partajat: AWS certifică infrastructura; TU trebuie să o folosești corect.\"\n            }\n        ],\n        relatedConcepts: [\n            \"shared-responsibility\"\n        ],\n        relatedServices: [\n            \"kms\",\n            \"cloudtrail\",\n            \"config\"\n        ],\n        docsUrl: \"https://aws.amazon.com/compliance/programs/\",\n        examFrequency: \"medium\"\n    },\n    {\n        id: \"iam-best-practices\",\n        title: {\n            en: \"IAM Best Practices\",\n            ro: \"Best Practices IAM\"\n        },\n        tagline: {\n            en: \"The right way to manage AWS identities — from day one.\",\n            ro: \"Modul corect de a gestiona identitățile AWS — din ziua 1.\"\n        },\n        topic: \"compliance\",\n        aliases: [\n            \"iam best practices\",\n            \"security best practices\",\n            \"mfa\",\n            \"least privilege\",\n            \"root\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"Top 10 IAM rules\",\n                    ro: \"Top 10 reguli IAM\"\n                },\n                body: {\n                    en: \"1. NEVER use the root account for daily work — use it only for billing/account setup\\n2. Enable MFA on root and all privileged users\\n3. Use IAM Users + Groups (not policies attached directly to users)\\n4. Apply least privilege — grant only what is needed\\n5. Use IAM Roles for EC2, Lambda, and cross-account access (NEVER hardcode keys)\\n6. Rotate access keys regularly (or use temporary credentials via STS)\\n7. Use strong password policies\\n8. Use IAM Access Analyzer to find risky resources\\n9. Audit access with CloudTrail\\n10. Use IAM Identity Center (SSO) for human users; IAM users for apps\",\n                    ro: \"1. NU folosi root pentru muncă zilnică — doar facturare/setup\\n2. Activează MFA pe root și toți userii privilegiați\\n3. Folosește IAM Users + Groups (nu politici direct pe useri)\\n4. Least privilege — dă doar ce e necesar\\n5. Folosește IAM Roles pentru EC2, Lambda, cross-account (NICIODATĂ chei hardcoded)\\n6. Rotește access keys regulat (sau folosește credențiale temporare via STS)\\n7. Politici parole puternice\\n8. Folosește IAM Access Analyzer pentru a găsi resurse riscante\\n9. Audit cu CloudTrail\\n10. Folosește IAM Identity Center (SSO) pentru utilizatori umani; IAM users pentru aplicații\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"Root: enable MFA, use only for setup/billing.\",\n                ro: \"Root: activează MFA, folosește doar pentru setup/facturare.\"\n            },\n            {\n                en: \"IAM is GLOBAL (not regional).\",\n                ro: \"IAM e GLOBAL (nu regional).\"\n            },\n            {\n                en: \"IAM is FREE.\",\n                ro: \"IAM e GRATUIT.\"\n            },\n            {\n                en: \"Use IAM Roles for AWS services — never hardcode access keys.\",\n                ro: \"Folosește IAM Roles pentru servicii AWS — niciodată chei hardcoded.\"\n            }\n        ],\n        relatedConcepts: [\n            \"shared-responsibility\"\n        ],\n        relatedServices: [\n            \"iam\",\n            \"cognito\",\n            \"iamic\",\n            \"cloudtrail\"\n        ],\n        docsUrl: \"https://docs.aws.amazon.com/IAM/latest/UserGuide/best-practices.html\",\n        examFrequency: \"high\"\n    }\n];\nconst caf = [\n    {\n        id: \"caf\",\n        title: {\n            en: \"Cloud Adoption Framework (CAF)\",\n            ro: \"Cloud Adoption Framework (CAF)\"\n        },\n        tagline: {\n            en: \"AWS roadmap for organizations migrating to the cloud — 6 perspectives.\",\n            ro: \"Roadmap AWS pentru organizații \\xeen migrare la cloud — 6 perspective.\"\n        },\n        topic: \"caf\",\n        aliases: [\n            \"caf\",\n            \"cloud adoption\",\n            \"migration framework\",\n            \"6 perspectives\"\n        ],\n        sections: [\n            {\n                heading: {\n                    en: \"The 6 perspectives\",\n                    ro: \"Cele 6 perspective\"\n                },\n                body: {\n                    en: \"Business capabilities (focus: business outcomes):\\n1. Business — value & ROI\\n2. People — culture & training\\n3. Governance — risk & compliance\\n\\nTechnical capabilities (focus: technology):\\n4. Platform — infrastructure & apps\\n5. Security — confidentiality & integrity\\n6. Operations — manageability & operations\",\n                    ro: \"Capabilități business (focus: rezultate business):\\n1. Business — valoare & ROI\\n2. People — cultură & training\\n3. Governance — risc & compliance\\n\\nCapabilități tehnice (focus: tehnologie):\\n4. Platform — infrastructură & aplicații\\n5. Security — confidențialitate & integritate\\n6. Operations — manageability & operații\"\n                }\n            },\n            {\n                heading: {\n                    en: \"The 7 Rs of migration\",\n                    ro: \"Cele 7 R-uri ale migrării\"\n                },\n                body: {\n                    en: \"- Rehost (lift-and-shift): move as-is to EC2 (use Application Migration Service)\\n- Replatform (lift-tinker-shift): minor cloud optimizations\\n- Repurchase: buy a SaaS replacement\\n- Refactor / Re-architect: rewrite cloud-native\\n- Retire: shut down\\n- Retain: keep on-premises (for now)\\n- Relocate: VMware Cloud on AWS\",\n                    ro: \"- Rehost (lift-and-shift): mut as-is pe EC2 (Application Migration Service)\\n- Replatform (lift-tinker-shift): optimizări cloud minore\\n- Repurchase: cumpăr \\xeenlocuitor SaaS\\n- Refactor / Re-architect: rescris cloud-native\\n- Retire: \\xeenchid\\n- Retain: păstrez on-premises (deocamdată)\\n- Relocate: VMware Cloud on AWS\"\n                }\n            }\n        ],\n        keyFacts: [\n            {\n                en: \"CAF has 6 perspectives split into business and technical.\",\n                ro: \"CAF are 6 perspective: business + tehnice.\"\n            },\n            {\n                en: \"7 Rs of migration are commonly tested.\",\n                ro: \"7 R-uri de migrare sunt frecvent testate.\"\n            },\n            {\n                en: \"Rehost = lift-and-shift = the fastest migration path.\",\n                ro: \"Rehost = lift-and-shift = cea mai rapidă migrare.\"\n            }\n        ],\n        relatedConcepts: [\n            \"cloud-advantages\"\n        ],\n        relatedServices: [\n            \"migrationhub\",\n            \"dms\",\n            \"applicationmigrationservice\"\n        ],\n        docsUrl: \"https://aws.amazon.com/professional-services/CAF/\",\n        examFrequency: \"medium\"\n    }\n];\nconst concepts = [\n    ...globalInfrastructure,\n    ...sharedResponsibility,\n    ...wellArchitected,\n    ...cloudFundamentals,\n    ...pricing,\n    ...compliance,\n    ...caf\n];\nfunction getConceptById(id) {\n    return concepts.find((c)=>c.id === id);\n}\nconst TOPIC_LABELS = {\n    \"global-infrastructure\": {\n        en: \"Global Infrastructure\",\n        ro: \"Infrastructură Globală\"\n    },\n    \"shared-responsibility\": {\n        en: \"Shared Responsibility\",\n        ro: \"Responsabilitate Partajată\"\n    },\n    \"well-architected\": {\n        en: \"Well-Architected\",\n        ro: \"Well-Architected\"\n    },\n    \"cloud-fundamentals\": {\n        en: \"Cloud Fundamentals\",\n        ro: \"Fundamentele Cloud\"\n    },\n    pricing: {\n        en: \"Pricing\",\n        ro: \"Prețuri\"\n    },\n    support: {\n        en: \"Support\",\n        ro: \"Suport\"\n    },\n    compliance: {\n        en: \"Compliance & Security\",\n        ro: \"Compliance & Securitate\"\n    },\n    caf: {\n        en: \"Cloud Adoption Framework\",\n        ro: \"Cloud Adoption Framework\"\n    }\n};\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/concepts.ts\n");

