eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   cloudConceptsQuestions: () => (/* binding */ cloudConceptsQuestions)\n/* harmony export */ });\n/**\n * CLF-C02 Domain 1: Cloud Concepts (24% of exam, ~16 questions of 65).\n * Topics: cloud value, AWS Well-Architected, cloud economics, migration strategies.\n *\n * Source mix: Stephane Maarek course + AWS Cloud Practitioner Exam Guide.\n */ const cloudConceptsQuestions = [\n    {\n        id: \"cc-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: \"Which cloud computing model gives the customer the MOST control over the operating system?\",\n            ro: \"Care model cloud \\xeei dă clientului cel mai MULT control asupra sistemului de operare?\"\n        },\n        options: [\n            {\n                en: \"Software as a Service (SaaS)\",\n                ro: \"Software as a Service (SaaS)\"\n            },\n            {\n                en: \"Platform as a Service (PaaS)\",\n                ro: \"Platform as a Service (PaaS)\"\n            },\n            {\n                en: \"Infrastructure as a Service (IaaS)\",\n                ro: \"Infrastructure as a Service (IaaS)\"\n            },\n            {\n                en: \"Function as a Service (FaaS)\",\n                ro: \"Function as a Service (FaaS)\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"IaaS (e.g., EC2) gives you full control of the OS — you patch it, install software, configure firewalls. PaaS (e.g., Beanstalk) abstracts the OS. SaaS (e.g., WorkMail) abstracts everything except the data.\",\n            ro: \"IaaS (ex: EC2) \\xeeți dă control deplin asupra OS-ului — faci patch, instalezi software, firewall. PaaS (ex: Beanstalk) abstractizează OS-ul. SaaS (ex: WorkMail) abstractizează tot mai puțin datele.\"\n        },\n        relatedServices: [\n            \"ec2\",\n            \"beanstalk\"\n        ]\n    },\n    {\n        id: \"cc-2\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: \"A startup wants to deploy a global application without managing infrastructure. Which characteristic of cloud computing is MOST relevant?\",\n            ro: \"Un startup vrea să deployeze o aplicație globală fără să gestioneze infrastructură. Care caracteristică cloud e cea mai relevantă?\"\n        },\n        options: [\n            {\n                en: \"Long-term capital commitment\",\n                ro: \"Angajament de capital pe termen lung\"\n            },\n            {\n                en: \"Global reach within minutes\",\n                ro: \"Acoperire globală \\xeen minute\"\n            },\n            {\n                en: \"Single point of failure\",\n                ro: \"Punct unic de defect\"\n            },\n            {\n                en: \"Manual capacity planning\",\n                ro: \"Planificare manuală a capacității\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"AWS lets you deploy to multiple Regions in minutes, giving global reach without buying servers in each country. This is one of the 6 advantages of cloud computing.\",\n            ro: \"AWS \\xeeți permite să deployezi \\xeen mai multe Regiuni \\xeen minute, oferind acoperire globală fără achiziții de servere \\xeen fiecare țară. E unul din cele 6 avantaje cloud.\"\n        },\n        relatedServices: [\n            \"cloudfront\",\n            \"route53\"\n        ]\n    },\n    {\n        id: \"cc-3\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"well-architected\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which Well-Architected pillar focuses on running and monitoring systems and continuously improving processes?\",\n            ro: \"Care pilon Well-Architected se concentrează pe rularea/monitorizarea sistemelor și \\xeembunătățirea continuă?\"\n        },\n        options: [\n            {\n                en: \"Performance Efficiency\",\n                ro: \"Performance Efficiency\"\n            },\n            {\n                en: \"Operational Excellence\",\n                ro: \"Operational Excellence\"\n            },\n            {\n                en: \"Reliability\",\n                ro: \"Reliability\"\n            },\n            {\n                en: \"Cost Optimization\",\n                ro: \"Cost Optimization\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Operational Excellence covers running, monitoring, and improving processes. It includes IaC, small reversible changes, and learning from failures.\",\n            ro: \"Operational Excellence acoperă rularea, monitorizarea și \\xeembunătățirea proceselor. Include IaC, schimbări mici reversibile, \\xeenvățarea din eșecuri.\"\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"well-architected\"\n        ]\n    },\n    {\n        id: \"cc-4\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"well-architected\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: \"Which Well-Architected pillar was added in 2021 and focuses on environmental impact?\",\n            ro: \"Care pilon Well-Architected a fost adăugat \\xeen 2021 și se concentrează pe impactul ecologic?\"\n        },\n        options: [\n            {\n                en: \"Performance Efficiency\",\n                ro: \"Performance Efficiency\"\n            },\n            {\n                en: \"Sustainability\",\n                ro: \"Sustainability\"\n            },\n            {\n                en: \"Cost Optimization\",\n                ro: \"Cost Optimization\"\n            },\n            {\n                en: \"Operational Excellence\",\n                ro: \"Operational Excellence\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Sustainability is the 6th pillar (added late 2021): minimize environmental impact via efficient resource use, right-sizing, and managed services that share infrastructure.\",\n            ro: \"Sustainability e al 6-lea pilon (adăugat la sf\\xe2rșitul lui 2021): minimizezi impactul ecologic prin resurse eficiente, right-sizing și servicii managed care partajează infrastructura.\"\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"well-architected\"\n        ]\n    },\n    {\n        id: \"cc-5\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"caf\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"aws-docs\",\n        question: {\n            en: \"A company plans to migrate by buying a SaaS replacement for an on-premises CRM system. Which of the 7 Rs is this?\",\n            ro: \"O companie vrea să migreze cumpăr\\xe2nd un SaaS care \\xeenlocuiește un CRM on-prem. Care din cei 7 R e acesta?\"\n        },\n        options: [\n            {\n                en: \"Rehost\",\n                ro: \"Rehost\"\n            },\n            {\n                en: \"Replatform\",\n                ro: \"Replatform\"\n            },\n            {\n                en: \"Repurchase\",\n                ro: \"Repurchase\"\n            },\n            {\n                en: \"Refactor\",\n                ro: \"Refactor\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Repurchase = buy a SaaS replacement (e.g., on-prem CRM → Salesforce). Rehost = lift-and-shift to EC2. Replatform = small cloud optimizations. Refactor = full rewrite cloud-native.\",\n            ro: \"Repurchase = cumperi un SaaS \\xeenlocuitor. Rehost = lift-and-shift pe EC2. Replatform = optimizări cloud minore. Refactor = rescriere completă cloud-native.\"\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"caf\"\n        ]\n    },\n    {\n        id: \"cc-6\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: '\"Stop guessing capacity\" is a benefit of cloud computing because:',\n            ro: '\"Stop guessing capacity\" e un beneficiu cloud pentru că:'\n        },\n        options: [\n            {\n                en: \"AWS predicts your traffic for you\",\n                ro: \"AWS prezice traficul \\xeen locul tău\"\n            },\n            {\n                en: \"Auto Scaling automatically adjusts capacity to actual demand\",\n                ro: \"Auto Scaling ajustează automat capacitatea la cererea reală\"\n            },\n            {\n                en: \"You must commit to 3 years of capacity\",\n                ro: \"Trebuie să te angajezi pe 3 ani\"\n            },\n            {\n                en: \"Capacity is fixed at account creation\",\n                ro: \"Capacitatea e fixată la crearea contului\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Auto Scaling adds/removes resources based on real demand, so you no longer overprovision (waste) or underprovision (outage). This is one of the 6 cloud advantages.\",\n            ro: \"Auto Scaling adaugă/elimină resurse după cererea reală — nu mai overprovisionezi (risipă) sau underprovisionezi (downtime). E unul din cele 6 avantaje cloud.\"\n        },\n        relatedServices: [\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"cc-7\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"well-architected\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which design principle of the cloud encourages testing on production scale environments?\",\n            ro: \"Care principiu de design cloud \\xeencurajează testarea pe environment-uri la scară producție?\"\n        },\n        options: [\n            {\n                en: '\"Stop guessing capacity\"',\n                ro: '\"Stop guessing capacity\"'\n            },\n            {\n                en: '\"Test systems at production scale\"',\n                ro: '\"Test systems at production scale\"'\n            },\n            {\n                en: '\"Drive architectures using data\"',\n                ro: '\"Drive architectures using data\"'\n            },\n            {\n                en: '\"Use the highest abstraction\"',\n                ro: '\"Use the highest abstraction\"'\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Cloud lets you spin up production-sized test environments cheaply (then tear them down) — impossible with fixed on-prem hardware. This is a key Well-Architected design principle.\",\n            ro: \"Cloud-ul \\xeeți permite să creezi environment-uri de test la dimensiunea producției ieftin (apoi le ștergi) — imposibil pe hardware on-prem fix. E un principiu cheie Well-Architected.\"\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"design-principles\"\n        ]\n    },\n    {\n        id: \"cc-8\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"caf\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: \"Which AWS Cloud Adoption Framework (CAF) perspective focuses on workforce skills and organizational change?\",\n            ro: \"Care perspectivă din Cloud Adoption Framework (CAF) se concentrează pe abilitățile echipei și schimbarea organizațională?\"\n        },\n        options: [\n            {\n                en: \"Business\",\n                ro: \"Business\"\n            },\n            {\n                en: \"People\",\n                ro: \"People\"\n            },\n            {\n                en: \"Platform\",\n                ro: \"Platform\"\n            },\n            {\n                en: \"Operations\",\n                ro: \"Operations\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"The People perspective covers culture, training, and organizational change. CAF has 6 perspectives: Business, People, Governance (business capabilities) + Platform, Security, Operations (technical capabilities).\",\n            ro: \"Perspectiva People acoperă cultura, training-ul și schimbarea organizațională. CAF are 6 perspective: Business, People, Governance (capabilități business) + Platform, Security, Operations (tehnice).\"\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"caf\"\n        ]\n    },\n    {\n        id: \"cc-9\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which deployment model combines on-premises infrastructure with AWS cloud services?\",\n            ro: \"Care model de deployment combină infrastructură on-premises cu servicii AWS cloud?\"\n        },\n        options: [\n            {\n                en: \"Public cloud\",\n                ro: \"Cloud public\"\n            },\n            {\n                en: \"Private cloud\",\n                ro: \"Cloud privat\"\n            },\n            {\n                en: \"Hybrid cloud\",\n                ro: \"Cloud hibrid\"\n            },\n            {\n                en: \"Multi-cloud\",\n                ro: \"Multi-cloud\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Hybrid cloud combines on-premises and cloud (e.g., via AWS Outposts, Direct Connect, or Storage Gateway). Multi-cloud uses multiple cloud providers — different concept.\",\n            ro: \"Hybrid cloud combină on-premises și cloud (ex: via Outposts, Direct Connect, Storage Gateway). Multi-cloud folosește mai mulți provideri cloud — alt concept.\"\n        },\n        relatedServices: [\n            \"outposts\"\n        ],\n        relatedConcepts: [\n            \"cloud-types\"\n        ]\n    },\n    {\n        id: \"cc-10\",\n        type: \"multiple_choice\",\n        difficulty: 3,\n        categories: [\n            \"well-architected\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"A company has decoupled its monolithic app into microservices using SQS queues. Which Well-Architected pillar does this primarily support?\",\n            ro: \"O companie a decuplat un monolit \\xeen microservicii folosind cozi SQS. Ce pilon Well-Architected sprijină asta \\xeen principal?\"\n        },\n        options: [\n            {\n                en: \"Cost Optimization\",\n                ro: \"Cost Optimization\"\n            },\n            {\n                en: \"Reliability\",\n                ro: \"Reliability\"\n            },\n            {\n                en: \"Sustainability\",\n                ro: \"Sustainability\"\n            },\n            {\n                en: \"Operational Excellence\",\n                ro: \"Operational Excellence\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Decoupling via queues is a core Reliability pattern: a failure in one component does not cascade to others. Messages buffer until the consumer recovers. This also helps Performance Efficiency.\",\n            ro: \"Decuplarea cu cozi e un pattern central de Reliability: defectul unui component nu se propagă. Mesajele se acumulează p\\xe2nă c\\xe2nd consumer-ul revine. Ajută și la Performance Efficiency.\"\n        },\n        relatedServices: [\n            \"sqs\",\n            \"sns\"\n        ],\n        relatedConcepts: [\n            \"well-architected\"\n        ]\n    },\n    {\n        id: \"cc-11\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: \"Elasticity in cloud computing means:\",\n            ro: \"Elasticitatea \\xeen cloud \\xeenseamnă:\"\n        },\n        options: [\n            {\n                en: \"You can stretch contracts up to 10 years\",\n                ro: \"Poți \\xeentinde contractele p\\xe2nă la 10 ani\"\n            },\n            {\n                en: \"You scale resources up and down to match demand automatically\",\n                ro: \"Scalezi resursele sus/jos automat după cerere\"\n            },\n            {\n                en: \"You pre-buy capacity for the next 5 years\",\n                ro: \"Cumperi capacitate pentru următorii 5 ani\"\n            },\n            {\n                en: \"You manually add servers each Monday\",\n                ro: \"Adaugi manual servere \\xeen fiecare luni\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Elasticity = automatic scale up AND scale down to match real demand. Different from scalability, which is the ability to grow capacity (one-way).\",\n            ro: \"Elasticitate = scalare automată sus ȘI jos după cererea reală. Diferit de scalabilitate, care e doar capacitatea de a crește (un singur sens).\"\n        },\n        relatedServices: [\n            \"ec2\",\n            \"lambda\"\n        ]\n    },\n    {\n        id: \"cc-12\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which type of high availability strategy uses synchronous replication across two Availability Zones?\",\n            ro: \"Care strategie de HA folosește replicare sincronă peste două AZ-uri?\"\n        },\n        options: [\n            {\n                en: \"Multi-Region active-passive\",\n                ro: \"Multi-Region active-passive\"\n            },\n            {\n                en: \"Multi-AZ standby (e.g., RDS Multi-AZ)\",\n                ro: \"Multi-AZ standby (ex: RDS Multi-AZ)\"\n            },\n            {\n                en: \"Single-AZ with snapshots\",\n                ro: \"Single-AZ cu snapshots\"\n            },\n            {\n                en: \"Edge caching via CloudFront\",\n                ro: \"Edge caching via CloudFront\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Multi-AZ standby (used by RDS, Aurora, ElastiCache) keeps a synchronous replica in a 2nd AZ for automatic failover. Cross-Region replication is asynchronous due to distance.\",\n            ro: \"Multi-AZ standby (folosit de RDS, Aurora, ElastiCache) ține o replică sincronă \\xeen alt AZ pentru failover automat. Replicarea cross-Region e asincronă din cauza distanței.\"\n        },\n        relatedServices: [\n            \"rds\",\n            \"aurora\"\n        ],\n        relatedConcepts: [\n            \"availability-zones\"\n        ]\n    },\n    {\n        id: \"cc-13\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"caf\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: 'Which migration strategy involves moving applications \"as-is\" with no code changes, sometimes called lift-and-shift?',\n            ro: 'Care strategie de migrare mută aplicațiile \"as-is\" fără modificări de cod, numită și lift-and-shift?'\n        },\n        options: [\n            {\n                en: \"Refactor\",\n                ro: \"Refactor\"\n            },\n            {\n                en: \"Rehost\",\n                ro: \"Rehost\"\n            },\n            {\n                en: \"Retire\",\n                ro: \"Retire\"\n            },\n            {\n                en: \"Retain\",\n                ro: \"Retain\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Rehost = lift-and-shift = move apps to AWS unchanged (typically to EC2 via AWS Application Migration Service). Fastest migration with minimal value-add.\",\n            ro: \"Rehost = lift-and-shift = muți aplicațiile pe AWS neschimbate (de obicei pe EC2 via Application Migration Service). Cea mai rapidă migrare, valoare adăugată minimă.\"\n        },\n        relatedServices: [\n            \"applicationmigrationservice\"\n        ],\n        relatedConcepts: [\n            \"caf\"\n        ]\n    },\n    {\n        id: \"cc-14\",\n        type: \"multiple_choice\",\n        difficulty: 3,\n        categories: [\n            \"well-architected\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Loose coupling in distributed systems is recommended because:\",\n            ro: \"Loose coupling \\xeen sistemele distribuite e recomandat pentru că:\"\n        },\n        options: [\n            {\n                en: \"It makes the system slower\",\n                ro: \"Face sistemul mai lent\"\n            },\n            {\n                en: \"It eliminates the need for monitoring\",\n                ro: \"Elimină nevoia de monitorizare\"\n            },\n            {\n                en: \"A failure in one component is contained and does not cascade\",\n                ro: \"Defectul unui component e izolat, nu se propagă\"\n            },\n            {\n                en: \"It guarantees a single point of failure\",\n                ro: \"Garantează un punct unic de defect\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Loose coupling (e.g., via SNS/SQS/EventBridge) isolates failures so each component can fail/restart independently. A core Reliability and Operational Excellence principle.\",\n            ro: \"Loose coupling (ex: via SNS/SQS/EventBridge) izolează defectele — fiecare component poate eșua/reporni independent. Principiu central de Reliability și Operational Excellence.\"\n        },\n        relatedServices: [\n            \"sqs\",\n            \"sns\",\n            \"eventbridge\"\n        ],\n        relatedConcepts: [\n            \"well-architected\"\n        ]\n    },\n    {\n        id: \"cc-15\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        examDomain: \"cloud-concepts\",\n        source: \"maarek\",\n        question: {\n            en: '\"Going global in minutes\" is enabled in AWS by:',\n            ro: '\"Globalizare \\xeen minute\" e activată \\xeen AWS prin:'\n        },\n        options: [\n            {\n                en: \"Creating a new AWS account per country\",\n                ro: \"Crearea unui cont AWS per țară\"\n            },\n            {\n                en: \"Deploying resources to multiple Regions and using Edge Locations\",\n                ro: \"Deployment \\xeen mai multe Regiuni + folosire Edge Locations\"\n            },\n            {\n                en: \"Buying CDN servers from a 3rd-party\",\n                ro: \"Cumpărare servere CDN de la terți\"\n            },\n            {\n                en: \"Manually shipping hard drives between countries\",\n                ro: \"Trimitere manuală hard disk-uri \\xeentre țări\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"AWS has 33 Regions and 450+ Edge Locations. You deploy in any Region in minutes via Console/CLI/CloudFormation, and CloudFront caches content at Edge Locations near users.\",\n            ro: \"AWS are 33 Regiuni și 450+ Edge Locations. Deployezi \\xeen orice Regiune \\xeen minute via Console/CLI/CloudFormation, iar CloudFront face cache la Edge Locations aproape de utilizatori.\"\n        },\n        relatedServices: [\n            \"cloudfront\",\n            \"route53\"\n        ],\n        relatedConcepts: [\n            \"regions\",\n            \"edge-locations\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/questions/cloud-concepts.ts\n");

