eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   securityQuestions: () => (/* binding */ securityQuestions)\n/* harmony export */ });\n/**\n * CLF-C02 Domain 2: Security and Compliance (30% of exam, ~20 questions of 65).\n * Topics: Shared Responsibility, IAM, encryption, compliance, security services.\n */ const securityQuestions = [\n    {\n        id: \"sec-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Under the Shared Responsibility Model, who manages physical security of AWS data centers?\",\n            ro: \"\\xcen Modelul Responsabilității Partajate, cine gestionează securitatea fizică a data centers AWS?\"\n        },\n        options: [\n            {\n                en: \"The customer\",\n                ro: \"Clientul\"\n            },\n            {\n                en: \"AWS\",\n                ro: \"AWS\"\n            },\n            {\n                en: \"Both AWS and customer\",\n                ro: \"Și AWS și clientul\"\n            },\n            {\n                en: \"A third-party auditor\",\n                ro: \"Un auditor terț\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: 'AWS manages \"security OF the cloud\" — physical hardware, data centers, network, hypervisors. Customers manage \"security IN the cloud\" — data, IAM, OS patches (for EC2), firewalls.',\n            ro: 'AWS gestionează \"securitatea CLOUD-ului\" — hardware fizic, data centers, rețea, hipervizoare. Clientul gestionează \"securitatea \\xceN cloud\" — date, IAM, patches OS (pentru EC2), firewall-uri.'\n        },\n        relatedServices: [],\n        relatedConcepts: [\n            \"shared-responsibility\"\n        ]\n    },\n    {\n        id: \"sec-2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which AWS service should you use to centrally store and rotate database passwords?\",\n            ro: \"Care serviciu AWS \\xeel folosești pentru a stoca centralizat și roti parolele de DB?\"\n        },\n        options: [\n            {\n                en: \"AWS KMS\",\n                ro: \"AWS KMS\"\n            },\n            {\n                en: \"AWS Secrets Manager\",\n                ro: \"AWS Secrets Manager\"\n            },\n            {\n                en: \"AWS Certificate Manager\",\n                ro: \"AWS Certificate Manager\"\n            },\n            {\n                en: \"Amazon Cognito\",\n                ro: \"Amazon Cognito\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Secrets Manager stores AND rotates secrets (DB passwords, API keys) automatically — costs $0.40 per secret/month. KMS stores encryption KEYS, not secrets. Parameter Store (Systems Manager) is a free alternative without auto-rotation.\",\n            ro: \"Secrets Manager stochează ȘI rotește secrete automat (parole DB, API keys) — costă $0.40/secret/lună. KMS stochează CHEI de criptare, nu secrete. Parameter Store (SSM) e alternativă gratuită fără auto-rotation.\"\n        },\n        relatedServices: [\n            \"secretsmanager\",\n            \"kms\",\n            \"systemsmanager\"\n        ]\n    },\n    {\n        id: \"sec-3\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which AWS service detects unusual API activity and potential threats using ML on CloudTrail and VPC logs?\",\n            ro: \"Care serviciu AWS detectează activitate neobișnuită + amenințări via ML pe CloudTrail și VPC logs?\"\n        },\n        options: [\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            },\n            {\n                en: \"AWS Shield\",\n                ro: \"AWS Shield\"\n            },\n            {\n                en: \"Amazon Inspector\",\n                ro: \"Amazon Inspector\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"GuardDuty = continuous threat detection using ML on CloudTrail, VPC Flow Logs, and DNS logs. Inspector scans EC2/ECR for vulnerabilities (CVE). Shield protects against DDoS. Config tracks resource state changes.\",\n            ro: \"GuardDuty = detecție continuă a amenințărilor cu ML pe CloudTrail, VPC Flow Logs, DNS logs. Inspector scanează EC2/ECR pentru vulnerabilități (CVE). Shield protejează la DDoS. Config urmărește schimbări de stare resurse.\"\n        },\n        relatedServices: [\n            \"guardduty\",\n            \"inspector\",\n            \"shield\",\n            \"config\"\n        ]\n    },\n    {\n        id: \"sec-4\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Which service uses ML to discover and protect sensitive data (PII) stored in Amazon S3?\",\n            ro: \"Care serviciu folosește ML pentru a descoperi și proteja date sensibile (PII) din S3?\"\n        },\n        options: [\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            },\n            {\n                en: \"Amazon Macie\",\n                ro: \"Amazon Macie\"\n            },\n            {\n                en: \"AWS Inspector\",\n                ro: \"AWS Inspector\"\n            },\n            {\n                en: \"AWS Detective\",\n                ro: \"AWS Detective\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Macie scans S3 buckets and uses ML to identify sensitive data (PII like SSN, credit cards, names). Alerts when public buckets contain such data. GuardDuty is for threat detection, not data classification.\",\n            ro: \"Macie scanează S3 cu ML și identifică date sensibile (PII: SSN, carduri, nume). Alertează c\\xe2nd bucket-uri publice conțin astfel de date. GuardDuty e pentru detecție amenințări, nu clasificare date.\"\n        },\n        relatedServices: [\n            \"macie\",\n            \"s3\"\n        ]\n    },\n    {\n        id: \"sec-5\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which is a recommended IAM best practice?\",\n            ro: \"Care e best practice IAM?\"\n        },\n        options: [\n            {\n                en: \"Use the root user for daily admin tasks\",\n                ro: \"Folosești root pentru sarcini admin zilnice\"\n            },\n            {\n                en: \"Hardcode access keys in source code\",\n                ro: \"Hardcodezi access keys \\xeen cod sursă\"\n            },\n            {\n                en: \"Apply least privilege and use IAM Roles for AWS services\",\n                ro: \"Aplici least privilege și folosești IAM Roles pentru servicii AWS\"\n            },\n            {\n                en: \"Disable MFA for convenience\",\n                ro: \"Dezactivezi MFA pentru confort\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Least privilege = grant only what is needed. Use IAM Roles for AWS services (EC2, Lambda) — they get temporary, auto-rotating credentials. Never hardcode access keys. Always enable MFA on root.\",\n            ro: \"Least privilege = dă doar ce e necesar. Folosește IAM Roles pentru servicii AWS (EC2, Lambda) — primesc credențiale temporare auto-rotative. Niciodată chei hardcoded. Activează MFA pe root.\"\n        },\n        relatedServices: [\n            \"iam\"\n        ],\n        relatedConcepts: [\n            \"iam-best-practices\"\n        ]\n    },\n    {\n        id: \"sec-6\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Where can you download AWS compliance reports (SOC, ISO, PCI DSS) for your auditors?\",\n            ro: \"De unde descarci rapoartele de compliance AWS (SOC, ISO, PCI DSS) pentru auditori?\"\n        },\n        options: [\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            },\n            {\n                en: \"AWS Artifact\",\n                ro: \"AWS Artifact\"\n            },\n            {\n                en: \"AWS CloudTrail\",\n                ro: \"AWS CloudTrail\"\n            },\n            {\n                en: \"AWS Trusted Advisor\",\n                ro: \"AWS Trusted Advisor\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"AWS Artifact is the self-service portal for compliance reports (SOC 1/2/3, ISO 27001, PCI DSS, HIPAA, FedRAMP). Free service. CloudTrail logs API activity but is not where you get compliance certificates.\",\n            ro: \"AWS Artifact e portalul self-service pentru rapoarte compliance (SOC 1/2/3, ISO 27001, PCI DSS, HIPAA, FedRAMP). Gratuit. CloudTrail loghează activitate API, nu de acolo iei certificatele.\"\n        },\n        relatedServices: [\n            \"artifact\"\n        ],\n        relatedConcepts: [\n            \"compliance-programs\"\n        ]\n    },\n    {\n        id: \"sec-7\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\",\n            \"network\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which AWS service protects web applications against SQL injection and XSS attacks?\",\n            ro: \"Care serviciu AWS protejează aplicații web la SQL injection și XSS?\"\n        },\n        options: [\n            {\n                en: \"AWS Shield Standard\",\n                ro: \"AWS Shield Standard\"\n            },\n            {\n                en: \"AWS WAF\",\n                ro: \"AWS WAF\"\n            },\n            {\n                en: \"AWS Network Firewall\",\n                ro: \"AWS Network Firewall\"\n            },\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"WAF (Web Application Firewall) protects at Layer 7 against SQL injection, XSS, bad bots. Attaches to ALB, API Gateway, CloudFront. Shield protects at Layer 3/4 (DDoS). Network Firewall is VPC-level packet filter.\",\n            ro: \"WAF (Web Application Firewall) protejează la Layer 7 contra SQL injection, XSS, bot-uri. Se atașează la ALB, API Gateway, CloudFront. Shield protejează la Layer 3/4 (DDoS). Network Firewall e packet filter la nivel VPC.\"\n        },\n        relatedServices: [\n            \"waf\",\n            \"shield\",\n            \"cloudfront\"\n        ]\n    },\n    {\n        id: \"sec-8\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"AWS Shield Standard is:\",\n            ro: \"AWS Shield Standard este:\"\n        },\n        options: [\n            {\n                en: \"A paid add-on costing $3,000/month\",\n                ro: \"Un add-on plătit, $3,000/lună\"\n            },\n            {\n                en: \"Automatically and freely enabled for all AWS customers\",\n                ro: \"Activat automat și gratuit pentru toți clienții AWS\"\n            },\n            {\n                en: \"Only available with Enterprise Support\",\n                ro: \"Disponibil doar cu Enterprise Support\"\n            },\n            {\n                en: \"A replacement for IAM\",\n                ro: \"Un \\xeenlocuitor pentru IAM\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Shield Standard is FREE and automatic for everyone — protects against common Layer 3/4 DDoS. Shield Advanced ($3,000/month) adds Layer 7 protection, 24/7 DDoS Response Team, and cost protection.\",\n            ro: \"Shield Standard e GRATUIT și automat pentru toți — protejează la DDoS Layer 3/4 comune. Shield Advanced ($3,000/lună) adaugă Layer 7, DDoS Response Team 24/7, cost protection.\"\n        },\n        relatedServices: [\n            \"shield\"\n        ]\n    },\n    {\n        id: \"sec-9\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which AWS service centrally manages security findings from GuardDuty, Inspector, Macie, and IAM Access Analyzer?\",\n            ro: \"Care serviciu agregă centralizat findings de securitate de la GuardDuty, Inspector, Macie, IAM Access Analyzer?\"\n        },\n        options: [\n            {\n                en: \"AWS Security Hub\",\n                ro: \"AWS Security Hub\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            },\n            {\n                en: \"Amazon Detective\",\n                ro: \"Amazon Detective\"\n            },\n            {\n                en: \"AWS Trusted Advisor\",\n                ro: \"AWS Trusted Advisor\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"Security Hub = single dashboard for findings across GuardDuty, Inspector, Macie, IAM Access Analyzer, plus partner tools. Runs continuous compliance checks against CIS, PCI DSS, AWS Foundational Security Best Practices.\",\n            ro: \"Security Hub = dashboard unic pentru findings de la GuardDuty, Inspector, Macie, IAM Access Analyzer, plus tool-uri partener. Rulează compliance checks continui contra CIS, PCI DSS, AWS Foundational Security Best Practices.\"\n        },\n        relatedServices: [\n            \"securityhub\",\n            \"guardduty\",\n            \"inspector\",\n            \"macie\"\n        ]\n    },\n    {\n        id: \"sec-10\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which feature of IAM allows users to log in using corporate Active Directory credentials?\",\n            ro: \"Care feature IAM permite userilor să se logheze cu credențiale Active Directory corporative?\"\n        },\n        options: [\n            {\n                en: \"IAM Access Keys\",\n                ro: \"IAM Access Keys\"\n            },\n            {\n                en: \"IAM Identity Center (formerly AWS SSO) with SAML 2.0\",\n                ro: \"IAM Identity Center (fost AWS SSO) cu SAML 2.0\"\n            },\n            {\n                en: \"IAM password policies\",\n                ro: \"IAM password policies\"\n            },\n            {\n                en: \"IAM Service-Linked Roles\",\n                ro: \"IAM Service-Linked Roles\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"IAM Identity Center (renamed from AWS SSO) lets users sign in once with their corporate identity (Active Directory, Okta, Azure AD) via SAML 2.0 and access multiple AWS accounts.\",\n            ro: \"IAM Identity Center (redenumit din AWS SSO) permite utilizatorilor să se logheze o singură dată cu identitatea corporativă (Active Directory, Okta, Azure AD) via SAML 2.0 și să acceseze mai multe conturi AWS.\"\n        },\n        relatedServices: [\n            \"iamic\",\n            \"iam\",\n            \"directoryservice\"\n        ]\n    },\n    {\n        id: \"sec-11\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Which is the BEST way to give an EC2 instance permissions to read from an S3 bucket?\",\n            ro: \"Care e MOD BUN să dai unei instanțe EC2 permisiuni să citească dintr-un bucket S3?\"\n        },\n        options: [\n            {\n                en: \"Store IAM access keys on the instance\",\n                ro: \"Stochezi IAM access keys pe instanță\"\n            },\n            {\n                en: \"Make the bucket public\",\n                ro: \"Faci bucket-ul public\"\n            },\n            {\n                en: \"Attach an IAM Role with S3 read permissions to the instance\",\n                ro: \"Atașezi un IAM Role cu permisiuni S3 read la instanță\"\n            },\n            {\n                en: \"Use the root account credentials\",\n                ro: \"Folosești credențialele root\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"IAM Roles for EC2 = secure best practice. Instance receives temporary credentials that auto-rotate via AWS Security Token Service (STS). No keys to leak.\",\n            ro: \"IAM Roles pentru EC2 = best practice sigur. Instanța primește credențiale temporare care se rotesc automat via STS. Nicio cheie de leak.\"\n        },\n        relatedServices: [\n            \"iam\",\n            \"ec2\",\n            \"s3\"\n        ]\n    },\n    {\n        id: \"sec-12\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"aws-docs\",\n        question: {\n            en: \"AWS Inspector primarily scans for:\",\n            ro: \"AWS Inspector scanează \\xeen principal pentru:\"\n        },\n        options: [\n            {\n                en: \"DDoS attacks on CloudFront\",\n                ro: \"Atacuri DDoS pe CloudFront\"\n            },\n            {\n                en: \"Software vulnerabilities (CVEs) on EC2 and ECR images\",\n                ro: \"Vulnerabilități software (CVEs) pe EC2 și imagini ECR\"\n            },\n            {\n                en: \"Sensitive data in S3 buckets\",\n                ro: \"Date sensibile \\xeen bucket-uri S3\"\n            },\n            {\n                en: \"IAM misconfigurations\",\n                ro: \"Configurări greșite IAM\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Inspector continuously scans EC2 instances and ECR container images for known software vulnerabilities (CVE database) and unintended network exposure. Macie does S3 data classification. IAM Access Analyzer does IAM.\",\n            ro: \"Inspector scanează continuu EC2 și imagini ECR pentru vulnerabilități software (CVE) și expuneri de rețea neintenționate. Macie face clasificare date S3. IAM Access Analyzer face IAM.\"\n        },\n        relatedServices: [\n            \"inspector\",\n            \"ec2\",\n            \"ecr\"\n        ]\n    },\n    {\n        id: \"sec-13\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: 'Encryption \"at rest\" refers to:',\n            ro: 'Criptarea \"at rest\" se referă la:'\n        },\n        options: [\n            {\n                en: \"Data being transmitted over the network\",\n                ro: \"Date transmise prin rețea\"\n            },\n            {\n                en: \"Data being processed by the CPU\",\n                ro: \"Date procesate de CPU\"\n            },\n            {\n                en: \"Data stored on disk (e.g., EBS, S3, RDS)\",\n                ro: \"Date stocate pe disc (ex: EBS, S3, RDS)\"\n            },\n            {\n                en: \"Data being printed\",\n                ro: \"Date printate\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: 'At rest = on disk/storage. AWS supports encryption at rest natively in EBS, S3, RDS, DynamoDB, etc. (often via KMS). \"In transit\" = over the network (TLS/SSL).',\n            ro: 'At rest = pe disc/storage. AWS suportă criptare at rest nativ \\xeen EBS, S3, RDS, DynamoDB etc. (deseori via KMS). \"In transit\" = prin rețea (TLS/SSL).'\n        },\n        relatedServices: [\n            \"kms\",\n            \"s3\",\n            \"ebs\",\n            \"rds\"\n        ]\n    },\n    {\n        id: \"sec-14\",\n        type: \"multiple_choice\",\n        difficulty: 3,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which AWS service helps INVESTIGATE the root cause of a security incident by visualizing relationships between findings?\",\n            ro: \"Care serviciu ajută la INVESTIGAREA cauzei unui incident de securitate vizualiz\\xe2nd relațiile \\xeentre findings?\"\n        },\n        options: [\n            {\n                en: \"AWS Security Hub\",\n                ro: \"AWS Security Hub\"\n            },\n            {\n                en: \"Amazon Detective\",\n                ro: \"Amazon Detective\"\n            },\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            },\n            {\n                en: \"AWS WAF\",\n                ro: \"AWS WAF\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Detective uses ML and graph analysis to investigate incidents — shows resource relationships and timeline. Security Hub aggregates findings, GuardDuty detects threats, but Detective is for FORENSIC investigation.\",\n            ro: \"Detective folosește ML și analiză graf pentru investigarea incidentelor — arată relații \\xeentre resurse și timeline. Security Hub agregă findings, GuardDuty detectează, dar Detective e pentru investigare FORENSICĂ.\"\n        },\n        relatedServices: [\n            \"detective\",\n            \"guardduty\",\n            \"securityhub\"\n        ]\n    },\n    {\n        id: \"sec-15\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Which is FREE for all AWS customers regardless of support plan?\",\n            ro: \"Care e GRATUIT pentru toți clienții AWS indiferent de support plan?\"\n        },\n        options: [\n            {\n                en: \"AWS Shield Advanced\",\n                ro: \"AWS Shield Advanced\"\n            },\n            {\n                en: \"IAM (Identity and Access Management)\",\n                ro: \"IAM (Identity and Access Management)\"\n            },\n            {\n                en: \"Enterprise Support TAM\",\n                ro: \"Enterprise Support TAM\"\n            },\n            {\n                en: \"AWS Professional Services\",\n                ro: \"AWS Professional Services\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"IAM, VPC, CloudFormation, Auto Scaling, AWS Organizations, AWS Cost Explorer are all FREE — you only pay for resources used through them. Shield Standard is also free; Advanced costs $3K/month.\",\n            ro: \"IAM, VPC, CloudFormation, Auto Scaling, AWS Organizations, Cost Explorer sunt toate GRATUITE — plătești doar resursele folosite prin ele. Shield Standard e gratuit; Advanced costă $3K/lună.\"\n        },\n        relatedServices: [\n            \"iam\"\n        ]\n    },\n    {\n        id: \"sec-16\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which AWS service provides SSL/TLS certificates for free for AWS services like CloudFront and ALB?\",\n            ro: \"Care serviciu AWS oferă certificate SSL/TLS gratuit pentru servicii ca CloudFront și ALB?\"\n        },\n        options: [\n            {\n                en: \"AWS Secrets Manager\",\n                ro: \"AWS Secrets Manager\"\n            },\n            {\n                en: \"AWS Certificate Manager (ACM)\",\n                ro: \"AWS Certificate Manager (ACM)\"\n            },\n            {\n                en: \"AWS KMS\",\n                ro: \"AWS KMS\"\n            },\n            {\n                en: \"AWS CloudHSM\",\n                ro: \"AWS CloudHSM\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"ACM provisions and auto-renews public SSL/TLS certificates for free, used with CloudFront, ALB, API Gateway, ELB. CloudHSM is dedicated hardware for FIPS 140-2 Level 3 compliance (paid).\",\n            ro: \"ACM provisiona și re\\xeennoiește automat certificate SSL/TLS publice gratuit, folosite cu CloudFront, ALB, API Gateway, ELB. CloudHSM e hardware dedicat pentru FIPS 140-2 Level 3 (plătit).\"\n        },\n        relatedServices: [\n            \"acm\",\n            \"cloudfront\"\n        ]\n    },\n    {\n        id: \"sec-17\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Which is NOT a feature of AWS Organizations?\",\n            ro: \"Care NU e feature al AWS Organizations?\"\n        },\n        options: [\n            {\n                en: \"Consolidated Billing across multiple accounts\",\n                ro: \"Consolidated Billing peste mai multe conturi\"\n            },\n            {\n                en: \"Service Control Policies (SCPs) to restrict permissions\",\n                ro: \"Service Control Policies (SCPs) pentru restricționare permisiuni\"\n            },\n            {\n                en: \"Multi-account management with OUs (Organizational Units)\",\n                ro: \"Gestionare multi-account cu OUs\"\n            },\n            {\n                en: \"Automatic patching of EC2 operating systems\",\n                ro: \"Patching automat al OS-urilor EC2\"\n            }\n        ],\n        correct: 3,\n        explanation: {\n            en: \"Organizations provides multi-account management, consolidated billing, SCPs, OUs. EC2 OS patching is via Systems Manager Patch Manager — different service.\",\n            ro: \"Organizations oferă management multi-account, billing consolidat, SCPs, OUs. Patching OS-uri EC2 e via Systems Manager Patch Manager — alt serviciu.\"\n        },\n        relatedServices: [\n            \"organizations\",\n            \"systemsmanager\"\n        ]\n    },\n    {\n        id: \"sec-18\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"A company wants ALL AWS API activity in their account logged for auditing. Which service?\",\n            ro: \"O companie vrea TOATĂ activitatea API AWS din cont log-ată pentru audit. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Amazon CloudWatch Logs\",\n                ro: \"Amazon CloudWatch Logs\"\n            },\n            {\n                en: \"AWS CloudTrail\",\n                ro: \"AWS CloudTrail\"\n            },\n            {\n                en: \"AWS X-Ray\",\n                ro: \"AWS X-Ray\"\n            },\n            {\n                en: \"VPC Flow Logs\",\n                ro: \"VPC Flow Logs\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudTrail logs every API call (who, what, when, from where). Critical for compliance audits. CloudWatch is for application metrics/logs. X-Ray traces request flow. VPC Flow Logs capture network packets.\",\n            ro: \"CloudTrail loghează fiecare apel API (cine, ce, c\\xe2nd, de unde). Critic pentru audit compliance. CloudWatch e pentru metrici/loguri aplicație. X-Ray urmărește flow request. VPC Flow Logs capturează pachete rețea.\"\n        },\n        relatedServices: [\n            \"cloudtrail\",\n            \"cloudwatch\"\n        ]\n    },\n    {\n        id: \"sec-19\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"maarek\",\n        question: {\n            en: \"Which compliance framework is for healthcare information in the United States?\",\n            ro: \"Care framework de compliance e pentru informații medicale \\xeen SUA?\"\n        },\n        options: [\n            {\n                en: \"GDPR\",\n                ro: \"GDPR\"\n            },\n            {\n                en: \"PCI DSS\",\n                ro: \"PCI DSS\"\n            },\n            {\n                en: \"HIPAA\",\n                ro: \"HIPAA\"\n            },\n            {\n                en: \"SOC 2\",\n                ro: \"SOC 2\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"HIPAA = US healthcare. AWS is HIPAA-eligible. GDPR = EU privacy. PCI DSS = payment cards. SOC = auditing standards. AWS holds 90+ certifications, viewable in AWS Artifact.\",\n            ro: \"HIPAA = sănătate SUA. AWS e HIPAA-eligible. GDPR = privacy UE. PCI DSS = carduri plată. SOC = standarde audit. AWS deține 90+ certificări, vizibile \\xeen AWS Artifact.\"\n        },\n        relatedServices: [\n            \"artifact\"\n        ],\n        relatedConcepts: [\n            \"compliance-programs\"\n        ]\n    },\n    {\n        id: \"sec-20\",\n        type: \"multiple_choice\",\n        difficulty: 3,\n        categories: [\n            \"security\"\n        ],\n        examDomain: \"security\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"A Service Control Policy (SCP) attached to an OU does which of the following?\",\n            ro: \"O Service Control Policy (SCP) atașată la un OU face care din următoarele?\"\n        },\n        options: [\n            {\n                en: \"Grants permissions to users\",\n                ro: \"Acordă permisiuni utilizatorilor\"\n            },\n            {\n                en: \"Sets the MAXIMUM permissions allowed for member accounts (cannot grant)\",\n                ro: \"Setează permisiunile MAXIME permise conturilor membre (nu acordă)\"\n            },\n            {\n                en: \"Replaces IAM policies\",\n                ro: \"\\xcenlocuiește politicile IAM\"\n            },\n            {\n                en: \"Auto-creates IAM users\",\n                ro: \"Creează automat IAM users\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"SCPs are guardrails — they DENY/RESTRICT what member accounts CAN do, but they cannot grant permissions. Effective permissions = intersection of SCP and IAM policy. Used in AWS Organizations.\",\n            ro: \"SCPs sunt guardrails — RESTRICȚIONEAZĂ ce POT face conturile membre, dar nu acordă permisiuni. Permisiuni efective = intersecția SCP și politică IAM. Folosite \\xeen AWS Organizations.\"\n        },\n        relatedServices: [\n            \"organizations\",\n            \"iam\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/questions/security.ts\n");

