eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   techServicesQuestions: () => (/* binding */ techServicesQuestions)\n/* harmony export */ });\n/**\n * CLF-C02 Domain 3: Cloud Technology and Services (34% of exam, ~22 questions of 65).\n * Topics: compute, storage, databases, networking, deployment.\n */ const techServicesQuestions = [\n    {\n        id: \"tech-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which is TRUE about AWS Lambda?\",\n            ro: \"Care e ADEVĂRAT despre AWS Lambda?\"\n        },\n        options: [\n            {\n                en: \"You manage the underlying servers\",\n                ro: \"Gestionezi serverele subiacente\"\n            },\n            {\n                en: \"You pay for idle time\",\n                ro: \"Plătești pentru timp idle\"\n            },\n            {\n                en: \"You pay only when functions run, billed in 1ms increments\",\n                ro: \"Plătești doar c\\xe2nd rulează, facturat \\xeen pași de 1ms\"\n            },\n            {\n                en: \"Functions can run for up to 24 hours\",\n                ro: \"Funcțiile pot rula p\\xe2nă la 24 ore\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Lambda = serverless. Pay only for execution time (1ms billing) and number of invocations. Max execution time is 15 minutes per invocation. No server management.\",\n            ro: \"Lambda = serverless. Plătești doar timpul de execuție (facturat la 1ms) și numărul de invocări. Max 15 min/invocare. Fără management de server.\"\n        },\n        relatedServices: [\n            \"lambda\"\n        ]\n    },\n    {\n        id: \"tech-2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"A team wants to run Docker containers without managing EC2 instances. Which service?\",\n            ro: \"O echipă vrea să ruleze containere Docker fără să gestioneze EC2. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Amazon ECS with EC2 launch type\",\n                ro: \"Amazon ECS cu launch type EC2\"\n            },\n            {\n                en: \"AWS Fargate\",\n                ro: \"AWS Fargate\"\n            },\n            {\n                en: \"AWS Batch\",\n                ro: \"AWS Batch\"\n            },\n            {\n                en: \"Amazon EMR\",\n                ro: \"Amazon EMR\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Fargate = serverless containers — runs on top of ECS or EKS but you do not manage EC2 instances, just specify CPU/memory. ECS with EC2 means YOU manage the instances. Batch is for HPC jobs. EMR is for Hadoop/Spark.\",\n            ro: \"Fargate = containere serverless — rulează peste ECS sau EKS dar nu gestionezi EC2, doar specifici CPU/memorie. ECS cu EC2 \\xeenseamnă TU gestionezi instanțele. Batch = job-uri HPC. EMR = Hadoop/Spark.\"\n        },\n        relatedServices: [\n            \"ecs\",\n            \"eks\",\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"tech-3\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"storage\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which S3 storage class is BEST for data accessed once a quarter with millisecond retrieval?\",\n            ro: \"Care clasă S3 e CEA MAI BUNĂ pentru date accesate o dată pe trimestru cu recuperare \\xeen milisecunde?\"\n        },\n        options: [\n            {\n                en: \"S3 Standard\",\n                ro: \"S3 Standard\"\n            },\n            {\n                en: \"S3 Standard-Infrequent Access (Standard-IA)\",\n                ro: \"S3 Standard-Infrequent Access (Standard-IA)\"\n            },\n            {\n                en: \"S3 Glacier Flexible Retrieval\",\n                ro: \"S3 Glacier Flexible Retrieval\"\n            },\n            {\n                en: \"S3 Glacier Deep Archive\",\n                ro: \"S3 Glacier Deep Archive\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Standard-IA = cheaper storage but with retrieval fee, ms latency, multi-AZ. Perfect for data accessed less than monthly. Glacier classes have minutes-to-hours retrieval. S3 Standard is for frequent access.\",\n            ro: \"Standard-IA = stocare mai ieftină dar cu fee la retrieval, latență ms, multi-AZ. Perfect pentru date accesate sub lunar. Clasele Glacier au recuperare minute-ore. S3 Standard e pentru acces frecvent.\"\n        },\n        relatedServices: [\n            \"s3\"\n        ]\n    },\n    {\n        id: \"tech-4\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"storage\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"EBS volumes are tied to:\",\n            ro: \"Volumele EBS sunt legate de:\"\n        },\n        options: [\n            {\n                en: \"A specific AWS Region (multi-AZ)\",\n                ro: \"O Regiune AWS specifică (multi-AZ)\"\n            },\n            {\n                en: \"A specific Availability Zone\",\n                ro: \"Un AZ specific\"\n            },\n            {\n                en: \"Multiple Regions globally\",\n                ro: \"Mai multe Regiuni global\"\n            },\n            {\n                en: \"CloudFront Edge Locations\",\n                ro: \"Edge Locations CloudFront\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"EBS = single-AZ storage attached to one EC2 instance at a time. To use across AZs, use EFS (NFS) or copy via snapshot. EBS volumes are auto-replicated within their AZ for durability.\",\n            ro: \"EBS = stocare single-AZ atașată la o singură EC2 la un moment dat. Pentru cross-AZ folosește EFS (NFS) sau copiezi via snapshot. Volumele EBS sunt replicate auto \\xeen AZ-ul lor pentru durabilitate.\"\n        },\n        relatedServices: [\n            \"ebs\",\n            \"efs\",\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"tech-5\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"database\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which AWS database is MOST suitable for a high-traffic gaming leaderboard requiring single-digit ms latency?\",\n            ro: \"Care DB AWS e cea mai potrivită pentru un leaderboard de gaming cu trafic mare și latență sub 10ms?\"\n        },\n        options: [\n            {\n                en: \"Amazon RDS for PostgreSQL\",\n                ro: \"Amazon RDS pentru PostgreSQL\"\n            },\n            {\n                en: \"Amazon DynamoDB\",\n                ro: \"Amazon DynamoDB\"\n            },\n            {\n                en: \"Amazon Redshift\",\n                ro: \"Amazon Redshift\"\n            },\n            {\n                en: \"Amazon Neptune\",\n                ro: \"Amazon Neptune\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"DynamoDB = serverless NoSQL with consistent single-digit ms latency at any scale. Perfect for gaming, IoT, mobile apps. RDS is relational. Redshift is data warehouse. Neptune is graph DB.\",\n            ro: \"DynamoDB = NoSQL serverless cu latență consistentă sub 10ms la orice scală. Ideal pentru gaming, IoT, mobile. RDS e relațional. Redshift e data warehouse. Neptune e DB graf.\"\n        },\n        relatedServices: [\n            \"dynamodb\"\n        ]\n    },\n    {\n        id: \"tech-6\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"database\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Amazon Aurora is compatible with which database engines?\",\n            ro: \"Amazon Aurora e compatibil cu ce motoare DB?\"\n        },\n        options: [\n            {\n                en: \"MySQL and PostgreSQL\",\n                ro: \"MySQL și PostgreSQL\"\n            },\n            {\n                en: \"Oracle and SQL Server\",\n                ro: \"Oracle și SQL Server\"\n            },\n            {\n                en: \"MongoDB and Redis\",\n                ro: \"MongoDB și Redis\"\n            },\n            {\n                en: \"Cassandra and Couchbase\",\n                ro: \"Cassandra și Couchbase\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"Aurora is AWS-built relational DB compatible with MySQL and PostgreSQL — up to 5x faster than MySQL, 3x faster than Postgres. Supports up to 15 read replicas, auto-scales storage to 128 TB.\",\n            ro: \"Aurora e DB relațional AWS compatibil cu MySQL și PostgreSQL — p\\xe2nă la 5x mai rapid ca MySQL, 3x ca Postgres. Suportă p\\xe2nă la 15 read replicas, scalează auto p\\xe2nă la 128 TB.\"\n        },\n        relatedServices: [\n            \"aurora\",\n            \"rds\"\n        ]\n    },\n    {\n        id: \"tech-7\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"network\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"aws-docs\",\n        question: {\n            en: \"A company has a VPC and wants to connect it to their on-prem data center over a dedicated, private connection. Which service?\",\n            ro: \"O companie are VPC și vrea să-l conecteze la data center-ul on-prem printr-o conexiune dedicată privată. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Site-to-Site VPN\",\n                ro: \"Site-to-Site VPN\"\n            },\n            {\n                en: \"AWS Direct Connect\",\n                ro: \"AWS Direct Connect\"\n            },\n            {\n                en: \"AWS Transit Gateway\",\n                ro: \"AWS Transit Gateway\"\n            },\n            {\n                en: \"AWS PrivateLink\",\n                ro: \"AWS PrivateLink\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Direct Connect = physical, private fiber connection between on-prem and AWS. Lower latency, higher consistency, bypasses public internet. VPN goes over the internet (cheaper, encrypted, but slower).\",\n            ro: \"Direct Connect = conexiune fizică, fibră privată \\xeentre on-prem și AWS. Latență mică, consistentă, ocolește internetul public. VPN merge prin internet (mai ieftin, criptat, dar mai lent).\"\n        },\n        relatedServices: [\n            \"directconnect\",\n            \"vpc\"\n        ]\n    },\n    {\n        id: \"tech-8\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"network\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which Route 53 routing policy splits traffic by percentage between multiple endpoints (e.g., 70/30 for blue/green)?\",\n            ro: \"Care politică de routing Route 53 \\xeemparte traficul procentual \\xeentre endpoints (ex: 70/30 pentru blue/green)?\"\n        },\n        options: [\n            {\n                en: \"Latency-based\",\n                ro: \"Latency-based\"\n            },\n            {\n                en: \"Failover\",\n                ro: \"Failover\"\n            },\n            {\n                en: \"Weighted\",\n                ro: \"Weighted\"\n            },\n            {\n                en: \"Geolocation\",\n                ro: \"Geolocation\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Weighted routing = split traffic by percentage. Useful for canary deployments, A/B testing, blue/green. Failover = active/passive. Latency = lowest latency Region. Geolocation = by user country.\",\n            ro: \"Weighted routing = split procentual al traficului. Util pentru canary deployments, A/B testing, blue/green. Failover = activ/pasiv. Latency = Regiunea cu latența minimă. Geolocation = după țara userului.\"\n        },\n        relatedServices: [\n            \"route53\"\n        ]\n    },\n    {\n        id: \"tech-9\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"network\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"aws-docs\",\n        question: {\n            en: \"CloudFront is best described as:\",\n            ro: \"CloudFront e descris cel mai bine ca:\"\n        },\n        options: [\n            {\n                en: \"A managed VPN service\",\n                ro: \"Un VPN managed\"\n            },\n            {\n                en: \"A Content Delivery Network (CDN) using global Edge Locations\",\n                ro: \"Un CDN global prin Edge Locations\"\n            },\n            {\n                en: \"A relational database\",\n                ro: \"O bază de date relațională\"\n            },\n            {\n                en: \"An object storage service\",\n                ro: \"Un serviciu de obiect storage\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudFront caches content at 450+ Edge Locations near users for low latency. Integrates with S3, ALB, EC2, MediaPackage. Provides DDoS protection (Shield Standard) and WAF integration.\",\n            ro: \"CloudFront cachează conținut la 450+ Edge Locations aproape de utilizatori pentru latență mică. Integrare cu S3, ALB, EC2, MediaPackage. Oferă DDoS (Shield Standard) și integrare WAF.\"\n        },\n        relatedServices: [\n            \"cloudfront\",\n            \"s3\"\n        ]\n    },\n    {\n        id: \"tech-10\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\",\n            \"integration\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which is a fully-managed orchestration service that lets you build serverless workflows with steps and decisions?\",\n            ro: \"Care e un serviciu managed de orchestrare care permite workflow-uri serverless cu pași și decizii?\"\n        },\n        options: [\n            {\n                en: \"Amazon SQS\",\n                ro: \"Amazon SQS\"\n            },\n            {\n                en: \"AWS Step Functions\",\n                ro: \"AWS Step Functions\"\n            },\n            {\n                en: \"Amazon SNS\",\n                ro: \"Amazon SNS\"\n            },\n            {\n                en: \"AWS Batch\",\n                ro: \"AWS Batch\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Step Functions = visual workflow orchestrator. Define states (tasks, choices, parallel, wait, fail) in a state machine. Integrates with Lambda, ECS, SNS, SQS, Batch, Glue. Pay per state transition.\",\n            ro: \"Step Functions = orchestrator vizual de workflow. Definești stări (task-uri, decizii, paralel, wait, fail) \\xeen state machine. Integrare cu Lambda, ECS, SNS, SQS, Batch, Glue. Plătești per tranziție.\"\n        },\n        relatedServices: [\n            \"stepfunctions\",\n            \"lambda\"\n        ]\n    },\n    {\n        id: \"tech-11\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"storage\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"A company needs to physically transfer 50 PB of data into AWS. Which option is BEST?\",\n            ro: \"O companie trebuie să transfere fizic 50 PB de date \\xeen AWS. Care e CEA MAI BUNĂ opțiune?\"\n        },\n        options: [\n            {\n                en: \"AWS Snowcone\",\n                ro: \"AWS Snowcone\"\n            },\n            {\n                en: \"AWS Snowball Edge\",\n                ro: \"AWS Snowball Edge\"\n            },\n            {\n                en: \"AWS Snowmobile\",\n                ro: \"AWS Snowmobile\"\n            },\n            {\n                en: \"AWS DataSync\",\n                ro: \"AWS DataSync\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Snowmobile = 100 PB per truck (literally). Snowball Edge = up to 80 TB per device. Snowcone = up to 8 TB. DataSync transfers over network — too slow for petabytes.\",\n            ro: \"Snowmobile = 100 PB per camion (literal). Snowball Edge = p\\xe2nă la 80 TB per device. Snowcone = p\\xe2nă la 8 TB. DataSync e transfer prin rețea — prea lent pentru petabytes.\"\n        },\n        relatedServices: [\n            \"snowfamily\",\n            \"datasync\"\n        ]\n    },\n    {\n        id: \"tech-12\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which EC2 pricing option is BEST for a stateful database needing predictable cost over 3 years?\",\n            ro: \"Care opțiune de preț EC2 e CEA MAI BUNĂ pentru un DB stateful cu cost predictibil pe 3 ani?\"\n        },\n        options: [\n            {\n                en: \"Spot Instances\",\n                ro: \"Spot Instances\"\n            },\n            {\n                en: \"On-Demand\",\n                ro: \"On-Demand\"\n            },\n            {\n                en: \"Reserved Instances (3-year, all upfront)\",\n                ro: \"Reserved Instances (3 ani, all upfront)\"\n            },\n            {\n                en: \"Dedicated Hosts\",\n                ro: \"Dedicated Hosts\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Reserved Instances 3-year all upfront = up to 72% discount, predictable cost. Perfect for stateful, always-on workloads like DBs. Spot can be terminated. On-Demand has no discount. Dedicated Hosts are for compliance/licensing.\",\n            ro: \"Reserved Instances 3-year all upfront = p\\xe2nă la 72% reducere, cost predictibil. Perfect pentru workload-uri stateful, mereu pornite ca DB-uri. Spot poate fi oprit. On-Demand nu are reducere. Dedicated Hosts sunt pentru compliance/licențe.\"\n        },\n        relatedServices: [\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"tech-13\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"integration\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"aws-docs\",\n        question: {\n            en: \"Which AWS service is BEST for ingesting and processing real-time streaming data (e.g., clickstreams)?\",\n            ro: \"Care serviciu AWS e CEL MAI BUN pentru ingestia și procesarea datelor \\xeen timp real (ex: clickstreams)?\"\n        },\n        options: [\n            {\n                en: \"Amazon SQS\",\n                ro: \"Amazon SQS\"\n            },\n            {\n                en: \"Amazon Kinesis Data Streams\",\n                ro: \"Amazon Kinesis Data Streams\"\n            },\n            {\n                en: \"Amazon S3\",\n                ro: \"Amazon S3\"\n            },\n            {\n                en: \"AWS Glue\",\n                ro: \"AWS Glue\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Kinesis Data Streams = real-time streaming, supports multiple consumers, 7-365 day retention. SQS is point-to-point, max 14-day retention, no real ordering at scale. Glue is ETL.\",\n            ro: \"Kinesis Data Streams = streaming real-time, suportă mulți consumeri, retenție 7-365 zile. SQS e point-to-point, max 14 zile retenție, fără ordering real la scală. Glue e ETL.\"\n        },\n        relatedServices: [\n            \"kinesis\",\n            \"sqs\"\n        ]\n    },\n    {\n        id: \"tech-14\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"analytics\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which service lets you query data DIRECTLY in S3 using SQL, with no infrastructure to manage?\",\n            ro: \"Care serviciu permite să interoghezi date DIRECT \\xeen S3 folosind SQL, fără infrastructură de gestionat?\"\n        },\n        options: [\n            {\n                en: \"Amazon Redshift\",\n                ro: \"Amazon Redshift\"\n            },\n            {\n                en: \"Amazon Athena\",\n                ro: \"Amazon Athena\"\n            },\n            {\n                en: \"Amazon EMR\",\n                ro: \"Amazon EMR\"\n            },\n            {\n                en: \"AWS Glue\",\n                ro: \"AWS Glue\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Athena = serverless SQL on S3. Pay per TB scanned. Perfect for ad-hoc analysis. Redshift requires loading into a warehouse cluster. EMR runs Hadoop/Spark on EC2 (you manage). Glue is ETL.\",\n            ro: \"Athena = SQL serverless pe S3. Plătești per TB scanat. Perfect pentru analize ad-hoc. Redshift necesită \\xeencărcare \\xeen cluster warehouse. EMR rulează Hadoop/Spark pe EC2 (gestionezi). Glue e ETL.\"\n        },\n        relatedServices: [\n            \"athena\",\n            \"s3\",\n            \"redshift\"\n        ]\n    },\n    {\n        id: \"tech-15\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Elastic Load Balancer types include all of the following EXCEPT:\",\n            ro: \"Tipurile de Elastic Load Balancer le includ pe toate, EXCEPT\\xc2ND:\"\n        },\n        options: [\n            {\n                en: \"Application Load Balancer (ALB)\",\n                ro: \"Application Load Balancer (ALB)\"\n            },\n            {\n                en: \"Network Load Balancer (NLB)\",\n                ro: \"Network Load Balancer (NLB)\"\n            },\n            {\n                en: \"Gateway Load Balancer (GWLB)\",\n                ro: \"Gateway Load Balancer (GWLB)\"\n            },\n            {\n                en: \"Database Load Balancer (DLB)\",\n                ro: \"Database Load Balancer (DLB)\"\n            }\n        ],\n        correct: 3,\n        explanation: {\n            en: \"There is no DLB. AWS has 3 ELB types: ALB (Layer 7, HTTP/HTTPS), NLB (Layer 4, TCP/UDP, ultra-low latency), GWLB (Layer 3, third-party security appliances). Classic Load Balancer is deprecated.\",\n            ro: \"Nu există DLB. AWS are 3 tipuri ELB: ALB (Layer 7, HTTP/HTTPS), NLB (Layer 4, TCP/UDP, latență ultra-mică), GWLB (Layer 3, security appliances terți). Classic Load Balancer e deprecated.\"\n        },\n        relatedServices: [\n            \"elb\"\n        ]\n    },\n    {\n        id: \"tech-16\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Auto Scaling Groups (ASG) provide which benefit?\",\n            ro: \"Auto Scaling Groups (ASG) oferă ce beneficiu?\"\n        },\n        options: [\n            {\n                en: \"They reduce S3 costs\",\n                ro: \"Reduc costurile S3\"\n            },\n            {\n                en: \"They automatically replace unhealthy EC2 instances and scale capacity to demand\",\n                ro: \"\\xcenlocuiesc automat instanțele EC2 nesănătoase și scalează capacitatea la cerere\"\n            },\n            {\n                en: \"They encrypt EBS volumes\",\n                ro: \"Criptează volumele EBS\"\n            },\n            {\n                en: \"They migrate databases\",\n                ro: \"Migrează DB-uri\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"ASG: launches/terminates EC2 based on scaling policies (CPU %, schedule, predictive). Auto-replaces failed instances based on health checks. Free service — pay only for EC2 instances launched.\",\n            ro: \"ASG: lansează/oprește EC2 după policy-uri de scalare (CPU %, schedule, predictiv). \\xcenlocuiește auto instanțe defecte după health checks. Serviciu GRATUIT — plătești doar instanțele EC2.\"\n        },\n        relatedServices: [\n            \"ec2\",\n            \"elb\"\n        ]\n    },\n    {\n        id: \"tech-17\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"storage\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which feature of S3 helps protect against accidental deletion?\",\n            ro: \"Care feature S3 protejează la ștergere accidentală?\"\n        },\n        options: [\n            {\n                en: \"Cross-Region Replication\",\n                ro: \"Cross-Region Replication\"\n            },\n            {\n                en: \"S3 Versioning + MFA Delete\",\n                ro: \"S3 Versioning + MFA Delete\"\n            },\n            {\n                en: \"S3 Transfer Acceleration\",\n                ro: \"S3 Transfer Acceleration\"\n            },\n            {\n                en: \"S3 Storage Lens\",\n                ro: \"S3 Storage Lens\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Versioning keeps old versions of objects. MFA Delete requires MFA token to permanently delete versions or disable versioning. Replication is for DR. Transfer Acceleration uses CloudFront for fast uploads.\",\n            ro: \"Versioning păstrează versiuni vechi ale obiectelor. MFA Delete cere token MFA pentru ștergere permanentă sau dezactivare versioning. Replication e pentru DR. Transfer Acceleration folosește CloudFront pentru upload rapid.\"\n        },\n        relatedServices: [\n            \"s3\"\n        ]\n    },\n    {\n        id: \"tech-18\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"aws-docs\",\n        question: {\n            en: \"A developer wants to run a CI/CD pipeline on AWS that builds, tests, and deploys code. Which combination?\",\n            ro: \"Un dezvoltator vrea să ruleze un pipeline CI/CD pe AWS care build-uie, testează și deployează cod. Ce combinație?\"\n        },\n        options: [\n            {\n                en: \"CodeCommit + CodeBuild + CodeDeploy + CodePipeline\",\n                ro: \"CodeCommit + CodeBuild + CodeDeploy + CodePipeline\"\n            },\n            {\n                en: \"EC2 + RDS + S3\",\n                ro: \"EC2 + RDS + S3\"\n            },\n            {\n                en: \"Lambda + DynamoDB\",\n                ro: \"Lambda + DynamoDB\"\n            },\n            {\n                en: \"Glue + Athena + Redshift\",\n                ro: \"Glue + Athena + Redshift\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"AWS Code* suite: CodeCommit (Git repos), CodeBuild (compile/test), CodeDeploy (release to EC2/Lambda/ECS), CodePipeline (orchestrate the whole pipeline).\",\n            ro: \"Suita AWS Code*: CodeCommit (Git repos), CodeBuild (compile/test), CodeDeploy (release la EC2/Lambda/ECS), CodePipeline (orchestrează tot pipeline-ul).\"\n        },\n        relatedServices: [\n            \"codepipeline\"\n        ]\n    },\n    {\n        id: \"tech-19\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which service automatically deploys an application from your code without you managing the underlying infrastructure?\",\n            ro: \"Care serviciu deployează automat o aplicație din codul tău fără să gestionezi infrastructura?\"\n        },\n        options: [\n            {\n                en: \"AWS CloudFormation\",\n                ro: \"AWS CloudFormation\"\n            },\n            {\n                en: \"AWS Elastic Beanstalk\",\n                ro: \"AWS Elastic Beanstalk\"\n            },\n            {\n                en: \"AWS Systems Manager\",\n                ro: \"AWS Systems Manager\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Elastic Beanstalk = PaaS. Upload code, AWS provisions EC2/ELB/ASG/RDS automatically. Service is FREE; you pay only for resources used. CloudFormation is IaC where YOU write templates.\",\n            ro: \"Elastic Beanstalk = PaaS. Uploadezi cod, AWS provisiona EC2/ELB/ASG/RDS automat. Serviciul e GRATUIT; plătești doar resurse. CloudFormation e IaC unde TU scrii template-urile.\"\n        },\n        relatedServices: [\n            \"beanstalk\",\n            \"cloudformation\"\n        ]\n    },\n    {\n        id: \"tech-20\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"network\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"A VPC subnet is:\",\n            ro: \"Un subnet VPC este:\"\n        },\n        options: [\n            {\n                en: \"Always public to the internet\",\n                ro: \"Mereu public la internet\"\n            },\n            {\n                en: \"A range of IP addresses inside a VPC, tied to a single Availability Zone\",\n                ro: \"Un range de IP-uri \\xeen VPC, legat de un singur AZ\"\n            },\n            {\n                en: \"A region-wide IP block\",\n                ro: \"Un bloc IP la nivel de Region\"\n            },\n            {\n                en: \"A type of EC2 instance\",\n                ro: \"Un tip de instanță EC2\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: 'Subnet = IP range (CIDR) in one AZ inside a VPC. \"Public\" subnets have an Internet Gateway route. \"Private\" subnets do not. Multi-AZ apps create one subnet per AZ.',\n            ro: 'Subnet = range IP (CIDR) \\xeentr-un AZ \\xeen VPC. Subnet \"public\" are rută la Internet Gateway. Subnet \"privat\" nu. Aplicațiile multi-AZ creează un subnet per AZ.'\n        },\n        relatedServices: [\n            \"vpc\"\n        ]\n    },\n    {\n        id: \"tech-21\",\n        type: \"multiple_choice\",\n        difficulty: 3,\n        categories: [\n            \"integration\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"tutorials-dojo\",\n        question: {\n            en: \"Which messaging service guarantees ordered processing of messages with FIFO semantics?\",\n            ro: \"Care serviciu de messaging garantează procesarea ordonată a mesajelor cu semantică FIFO?\"\n        },\n        options: [\n            {\n                en: \"Amazon SQS Standard queue\",\n                ro: \"Amazon SQS Standard queue\"\n            },\n            {\n                en: \"Amazon SQS FIFO queue\",\n                ro: \"Amazon SQS FIFO queue\"\n            },\n            {\n                en: \"Amazon SNS Standard topic\",\n                ro: \"Amazon SNS Standard topic\"\n            },\n            {\n                en: \"Amazon EventBridge bus\",\n                ro: \"Amazon EventBridge bus\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"SQS FIFO = exactly-once delivery, strict ordering, up to 300 msg/sec (3000 with batching). Standard SQS = best-effort ordering, at-least-once delivery, unlimited throughput.\",\n            ro: \"SQS FIFO = livrare exact-once, ordine strictă, p\\xe2nă la 300 msg/sec (3000 cu batching). SQS Standard = ordine best-effort, livrare at-least-once, throughput nelimitat.\"\n        },\n        relatedServices: [\n            \"sqs\"\n        ]\n    },\n    {\n        id: \"tech-22\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"management\"\n        ],\n        examDomain: \"tech-services\",\n        source: \"maarek\",\n        question: {\n            en: \"Which AWS service helps you visually design and provision infrastructure as code using YAML or JSON templates?\",\n            ro: \"Care serviciu te ajută să proiectezi vizual și să provisionezi infrastructură ca cod folosind YAML/JSON?\"\n        },\n        options: [\n            {\n                en: \"AWS Systems Manager\",\n                ro: \"AWS Systems Manager\"\n            },\n            {\n                en: \"AWS CloudFormation\",\n                ro: \"AWS CloudFormation\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            },\n            {\n                en: \"AWS Service Catalog\",\n                ro: \"AWS Service Catalog\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudFormation = AWS-native IaC. You write a YAML/JSON template; CloudFormation provisions all resources atomically with auto-rollback on failure. Free; pay only for resources. CDK generates CloudFormation from code.\",\n            ro: \"CloudFormation = IaC nativ AWS. Scrii template YAML/JSON; CloudFormation provisiona resurse atomic cu rollback automat la eșec. Gratuit; plătești doar resurse. CDK generează CloudFormation din cod.\"\n        },\n        relatedServices: [\n            \"cloudformation\"\n        ]\n    }\n];\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/questions/tech-services.ts\n");

