eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   DOMAIN_WEIGHTS: () => (/* binding */ DOMAIN_WEIGHTS),\n/* harmony export */   buildQuiz: () => (/* binding */ buildQuiz),\n/* harmony export */   buildWeightedExam: () => (/* binding */ buildWeightedExam),\n/* harmony export */   getDailyChallengeQuestions: () => (/* binding */ getDailyChallengeQuestions),\n/* harmony export */   getQuestionsByCategory: () => (/* binding */ getQuestionsByCategory),\n/* harmony export */   getQuestionsByDomain: () => (/* binding */ getQuestionsByDomain),\n/* harmony export */   getRandomQuestions: () => (/* binding */ getRandomQuestions),\n/* harmony export */   quizQuestions: () => (/* binding */ quizQuestions)\n/* harmony export */ });\n/* harmony import */ var _questions_cloud_concepts__WEBPACK_IMPORTED_MODULE_0__ = __webpack_require__(/*! ./questions/cloud-concepts */ \"(ssr)/./src/data/questions/cloud-concepts.ts\");\n/* harmony import */ var _questions_security__WEBPACK_IMPORTED_MODULE_1__ = __webpack_require__(/*! ./questions/security */ \"(ssr)/./src/data/questions/security.ts\");\n/* harmony import */ var _questions_tech_services__WEBPACK_IMPORTED_MODULE_2__ = __webpack_require__(/*! ./questions/tech-services */ \"(ssr)/./src/data/questions/tech-services.ts\");\n/* harmony import */ var _questions_billing_support__WEBPACK_IMPORTED_MODULE_3__ = __webpack_require__(/*! ./questions/billing-support */ \"(ssr)/./src/data/questions/billing-support.ts\");\n/* harmony import */ var _questions_extra__WEBPACK_IMPORTED_MODULE_4__ = __webpack_require__(/*! ./questions/extra */ \"(ssr)/./src/data/questions/extra.ts\");\n\n\n\n\n\n/**\n * AWS Certified Cloud Practitioner (CLF-C02) practice questions.\n * Curated from Stephane Maarek's CLF-C02 course (primary) + official AWS exam guide\n * + Tutorials Dojo + AWS Skill Builder cross-reference.\n *\n * Each question is tagged with `examDomain` for the 4 official CLF-C02 domains:\n *   - cloud-concepts (24%)\n *   - security (30%)\n *   - tech-services (34%)\n *   - billing-support (12%)\n */ /** Legacy (v0.2) bank — domain tags inferred at runtime in `quizQuestions`. */ const legacyQuestions = [\n    // ========================================================================\n    // GLOBAL INFRASTRUCTURE\n    // ========================================================================\n    {\n        id: \"q-az-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"global-infrastructure\"\n        ],\n        question: {\n            en: \"What is an AWS Availability Zone?\",\n            ro: \"Ce este un AWS Availability Zone?\"\n        },\n        options: [\n            {\n                en: \"A geographic area like us-east-1\",\n                ro: \"O zonă geografică precum us-east-1\"\n            },\n            {\n                en: \"One or more discrete data centers within a Region, with redundant power and networking\",\n                ro: \"Unul sau mai multe data centers discrete \\xeentr-o Regiune, cu alimentare și rețea redundante\"\n            },\n            {\n                en: \"A Content Delivery Network endpoint\",\n                ro: \"Un endpoint Content Delivery Network\"\n            },\n            {\n                en: \"A type of EC2 instance\",\n                ro: \"Un tip de instanță EC2\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"An AZ is one or more discrete data centers within a Region. They are physically separated but connected by low-latency, high-throughput private fiber. Use multiple AZs for High Availability.\",\n            ro: \"Un AZ este unul sau mai multe data centers discrete \\xeentr-o Regiune. Sunt separate fizic dar conectate prin fibră privată cu latență mică. Folosești mai multe AZ-uri pentru HA.\"\n        },\n        relatedServices: []\n    },\n    {\n        id: \"q-region-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"global-infrastructure\"\n        ],\n        question: {\n            en: \"How many Availability Zones does each AWS Region have at minimum?\",\n            ro: \"C\\xe2te AZ-uri are minim fiecare Regiune AWS?\"\n        },\n        options: [\n            {\n                en: \"1\",\n                ro: \"1\"\n            },\n            {\n                en: \"2\",\n                ro: \"2\"\n            },\n            {\n                en: \"3\",\n                ro: \"3\"\n            },\n            {\n                en: \"5\",\n                ro: \"5\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Each AWS Region has at least 3 Availability Zones. Most have 3, some have up to 6. This enables fault-tolerant architectures.\",\n            ro: \"Fiecare Regiune AWS are minim 3 AZ-uri. Majoritatea au 3, unele p\\xe2nă la 6. Permite arhitecturi tolerante la defecte.\"\n        },\n        relatedServices: []\n    },\n    {\n        id: \"q-edge-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"global-infrastructure\"\n        ],\n        question: {\n            en: \"A company wants to reduce latency for users worldwide accessing static website content. Which AWS infrastructure component is MOST appropriate?\",\n            ro: \"O companie vrea să reducă latența pentru utilizatorii globali care accesează conținut static. Care componentă AWS e MAI potrivită?\"\n        },\n        options: [\n            {\n                en: \"Multi-AZ deployment in one Region\",\n                ro: \"Deployment Multi-AZ \\xeentr-o Regiune\"\n            },\n            {\n                en: \"AWS Edge Locations via CloudFront\",\n                ro: \"Edge Locations AWS via CloudFront\"\n            },\n            {\n                en: \"Multiple EC2 instances in a single AZ\",\n                ro: \"Mai multe instanțe EC2 \\xeentr-un singur AZ\"\n            },\n            {\n                en: \"AWS Outposts\",\n                ro: \"AWS Outposts\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudFront uses 450+ Edge Locations to cache content close to users, reducing latency globally. Edge Locations are NOT full Regions — they only host specific services like CloudFront, Route 53, Shield, WAF.\",\n            ro: \"CloudFront folosește 450+ Edge Locations pentru cache aproape de utilizatori, reduc\\xe2nd latența global. Edge Locations NU sunt Regiuni complete — găzduiesc doar CloudFront, Route 53, Shield, WAF.\"\n        },\n        relatedServices: [\n            \"cloudfront\",\n            \"route53\"\n        ]\n    },\n    // ========================================================================\n    // SHARED RESPONSIBILITY\n    // ========================================================================\n    {\n        id: \"q-shared-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"shared-responsibility\"\n        ],\n        question: {\n            en: \"Under the AWS Shared Responsibility Model, who is responsible for patching the operating system on an EC2 instance?\",\n            ro: \"\\xcen Modelul Responsabilității Partajate, cine e responsabil de patching-ul OS-ului pe o instanță EC2?\"\n        },\n        options: [\n            {\n                en: \"AWS, always\",\n                ro: \"AWS, mereu\"\n            },\n            {\n                en: \"The customer\",\n                ro: \"Clientul\"\n            },\n            {\n                en: \"Both AWS and customer equally\",\n                ro: \"AWS și clientul \\xeen egală măsură\"\n            },\n            {\n                en: \"Neither — the OS does not need patching\",\n                ro: \"Niciunul — OS-ul nu necesită patching\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"For EC2 (IaaS), the customer is responsible for the guest OS, including patches, updates, and security configuration. AWS only manages the underlying hardware and hypervisor. For managed services like RDS, AWS handles OS patching.\",\n            ro: \"Pentru EC2 (IaaS), clientul răspunde de guest OS, inclusiv patches, update-uri, config securitate. AWS gestionează doar hardware-ul și hipervizorul. Pentru servicii managed ca RDS, AWS face patching la OS.\"\n        },\n        relatedServices: [\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"q-shared-2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"shared-responsibility\"\n        ],\n        question: {\n            en: \"Which of the following is ALWAYS the customer responsibility regardless of the AWS service used?\",\n            ro: \"Care este MEREU responsabilitatea clientului, indiferent de serviciul AWS folosit?\"\n        },\n        options: [\n            {\n                en: \"Physical security of data centers\",\n                ro: \"Securitatea fizică a data centers\"\n            },\n            {\n                en: \"IAM users, roles, and access policies\",\n                ro: \"IAM users, roles și politici de acces\"\n            },\n            {\n                en: \"Hypervisor patching\",\n                ro: \"Patching hipervizor\"\n            },\n            {\n                en: \"Network cabling between Regions\",\n                ro: \"Cabluri de rețea \\xeentre Regiuni\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"IAM (Identity and Access Management) is ALWAYS the customer's responsibility. AWS manages the IAM service infrastructure, but configuring users, groups, roles, and policies is up to you.\",\n            ro: \"IAM este MEREU responsabilitatea clientului. AWS gestionează infrastructura IAM, dar configurarea userilor, grupurilor, rolurilor și politicilor e treaba ta.\"\n        },\n        relatedServices: [\n            \"iam\"\n        ]\n    },\n    // ========================================================================\n    // EC2 / COMPUTE\n    // ========================================================================\n    {\n        id: \"q-ec2-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        question: {\n            en: \"A company runs a workload that can tolerate interruption and wants the lowest possible cost. Which EC2 pricing model should they use?\",\n            ro: \"O companie rulează un workload care tolerează \\xeentreruperi și vrea costul cel mai mic. Ce model de preț EC2?\"\n        },\n        options: [\n            {\n                en: \"On-Demand Instances\",\n                ro: \"On-Demand Instances\"\n            },\n            {\n                en: \"Reserved Instances (3-year)\",\n                ro: \"Reserved Instances (3 ani)\"\n            },\n            {\n                en: \"Spot Instances\",\n                ro: \"Spot Instances\"\n            },\n            {\n                en: \"Dedicated Hosts\",\n                ro: \"Dedicated Hosts\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Spot Instances offer up to 90% discount but can be terminated by AWS with a 2-minute notice when capacity is needed. Perfect for fault-tolerant, batch, or stateless workloads. Reserved Instances give max 72% off; On-Demand has no discount.\",\n            ro: \"Spot Instances oferă p\\xe2nă la 90% reducere dar pot fi oprite de AWS cu preaviz 2 min. Ideal pentru workloads tolerante la defecte, batch sau stateless. Reserved Instances dau maxim 72%; On-Demand nu are reducere.\"\n        },\n        relatedServices: [\n            \"ec2\"\n        ]\n    },\n    {\n        id: \"q-lambda-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        question: {\n            en: \"What is the maximum execution time for a single AWS Lambda invocation?\",\n            ro: \"Care este timpul maxim de execuție al unei invocări AWS Lambda?\"\n        },\n        options: [\n            {\n                en: \"5 minutes\",\n                ro: \"5 minute\"\n            },\n            {\n                en: \"15 minutes\",\n                ro: \"15 minute\"\n            },\n            {\n                en: \"1 hour\",\n                ro: \"1 oră\"\n            },\n            {\n                en: \"No limit\",\n                ro: \"Fără limită\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Lambda functions can run for up to 15 minutes per invocation. For longer-running compute, use AWS Batch, ECS, or EC2.\",\n            ro: \"Funcțiile Lambda pot rula p\\xe2nă la 15 minute per invocare. Pentru execuții mai lungi, folosește AWS Batch, ECS sau EC2.\"\n        },\n        relatedServices: [\n            \"lambda\",\n            \"batch\",\n            \"ecs\"\n        ]\n    },\n    {\n        id: \"q-beanstalk-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"compute\"\n        ],\n        question: {\n            en: \"A developer wants to upload application code and have AWS automatically provision EC2, ELB, Auto Scaling, and RDS without managing the infrastructure. Which service?\",\n            ro: \"Un dezvoltator vrea să uploadeze cod și AWS să provisioneze automat EC2, ELB, Auto Scaling și RDS fără să gestioneze infrastructura. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Amazon EC2\",\n                ro: \"Amazon EC2\"\n            },\n            {\n                en: \"AWS Elastic Beanstalk\",\n                ro: \"AWS Elastic Beanstalk\"\n            },\n            {\n                en: \"AWS CloudFormation\",\n                ro: \"AWS CloudFormation\"\n            },\n            {\n                en: \"AWS Lambda\",\n                ro: \"AWS Lambda\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Elastic Beanstalk is a Platform-as-a-Service (PaaS) — you upload code, AWS handles provisioning of EC2, ELB, ASG, RDS. The service itself is FREE; you only pay for resources used. CloudFormation is IaC but you write the templates yourself.\",\n            ro: \"Elastic Beanstalk e PaaS — uploadezi cod, AWS gestionează EC2, ELB, ASG, RDS. Serviciul e GRATUIT; plătești doar resursele. CloudFormation e IaC dar scrii template-urile.\"\n        },\n        relatedServices: [\n            \"beanstalk\",\n            \"cloudformation\"\n        ]\n    },\n    // ========================================================================\n    // STORAGE\n    // ========================================================================\n    {\n        id: \"q-s3-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"storage\"\n        ],\n        question: {\n            en: \"What is the maximum size of a single object in Amazon S3?\",\n            ro: \"Care este dimensiunea maximă a unui obiect S3?\"\n        },\n        options: [\n            {\n                en: \"5 MB\",\n                ro: \"5 MB\"\n            },\n            {\n                en: \"5 GB\",\n                ro: \"5 GB\"\n            },\n            {\n                en: \"5 TB\",\n                ro: \"5 TB\"\n            },\n            {\n                en: \"Unlimited\",\n                ro: \"Nelimitată\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"A single S3 object can be up to 5 TB. Note: a single PUT operation has a max of 5 GB; for larger objects you must use multipart upload.\",\n            ro: \"Un obiect S3 poate avea p\\xe2nă la 5 TB. Notă: un singur PUT poate fi de maxim 5 GB; pentru obiecte mai mari folosește multipart upload.\"\n        },\n        relatedServices: [\n            \"s3\"\n        ]\n    },\n    {\n        id: \"q-s3-2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"storage\"\n        ],\n        question: {\n            en: \"A company needs the cheapest S3 storage class for archives accessed once a year, with retrieval acceptable in 12 hours. Which class?\",\n            ro: \"O companie are nevoie de cea mai ieftină clasă S3 pentru arhive accesate o dată pe an, recuperare acceptabilă \\xeen 12 ore. Ce clasă?\"\n        },\n        options: [\n            {\n                en: \"S3 Standard\",\n                ro: \"S3 Standard\"\n            },\n            {\n                en: \"S3 Standard-Infrequent Access\",\n                ro: \"S3 Standard-Infrequent Access\"\n            },\n            {\n                en: \"S3 Glacier Flexible Retrieval\",\n                ro: \"S3 Glacier Flexible Retrieval\"\n            },\n            {\n                en: \"S3 Glacier Deep Archive\",\n                ro: \"S3 Glacier Deep Archive\"\n            }\n        ],\n        correct: 3,\n        explanation: {\n            en: \"Glacier Deep Archive is the cheapest storage class ($0.00099/GB-month), with retrieval times of 12-48 hours. Use it for long-term archives accessed rarely. Glacier Flexible Retrieval is 1-12h. Glacier Instant Retrieval is ms but more expensive.\",\n            ro: \"Glacier Deep Archive e cea mai ieftină ($0.00099/GB-lună), cu recuperare 12-48h. Pentru arhive accesate rar. Glacier Flexible: 1-12h. Glacier Instant: ms dar mai scump.\"\n        },\n        relatedServices: [\n            \"s3\",\n            \"glacier\"\n        ]\n    },\n    {\n        id: \"q-ebs-efs\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"storage\"\n        ],\n        question: {\n            en: \"Multiple EC2 instances in different Availability Zones need to share a Linux file system simultaneously. Which storage service?\",\n            ro: \"Mai multe instanțe EC2 din AZ-uri diferite trebuie să partajeze un file system Linux simultan. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Amazon EBS\",\n                ro: \"Amazon EBS\"\n            },\n            {\n                en: \"Amazon EFS\",\n                ro: \"Amazon EFS\"\n            },\n            {\n                en: \"Amazon S3\",\n                ro: \"Amazon S3\"\n            },\n            {\n                en: \"Instance Store\",\n                ro: \"Instance Store\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"EFS (Elastic File System) is a managed NFS file system that can be mounted by multiple EC2 instances across multiple AZs simultaneously. EBS is single-AZ and (mostly) single-instance. S3 is object storage, not a file system.\",\n            ro: \"EFS (Elastic File System) e un NFS managed care poate fi montat de mai multe EC2 din mai multe AZ-uri simultan. EBS e single-AZ și (\\xeen general) single-instanță. S3 e obiect storage, nu file system.\"\n        },\n        relatedServices: [\n            \"efs\",\n            \"ebs\",\n            \"s3\"\n        ]\n    },\n    // ========================================================================\n    // DATABASES\n    // ========================================================================\n    {\n        id: \"q-dynamo-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"database\"\n        ],\n        question: {\n            en: \"Which AWS service provides a fully-managed NoSQL database with single-digit millisecond latency?\",\n            ro: \"Care serviciu AWS oferă o bază NoSQL fully-managed cu latență sub 10 milisecunde?\"\n        },\n        options: [\n            {\n                en: \"Amazon RDS\",\n                ro: \"Amazon RDS\"\n            },\n            {\n                en: \"Amazon Aurora\",\n                ro: \"Amazon Aurora\"\n            },\n            {\n                en: \"Amazon DynamoDB\",\n                ro: \"Amazon DynamoDB\"\n            },\n            {\n                en: \"Amazon Redshift\",\n                ro: \"Amazon Redshift\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"DynamoDB is a fully-managed serverless NoSQL key-value and document database with consistent single-digit ms latency. RDS/Aurora are relational. Redshift is a data warehouse for analytics.\",\n            ro: \"DynamoDB e NoSQL serverless managed cu latență consistentă sub 10ms. RDS/Aurora sunt relaționale. Redshift e data warehouse pentru analitică.\"\n        },\n        relatedServices: [\n            \"dynamodb\",\n            \"rds\",\n            \"aurora\",\n            \"redshift\"\n        ]\n    },\n    {\n        id: \"q-rds-multi-az\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"database\"\n        ],\n        question: {\n            en: \"What does enabling Multi-AZ on an Amazon RDS instance provide?\",\n            ro: \"Ce oferă activarea Multi-AZ pe o instanță Amazon RDS?\"\n        },\n        options: [\n            {\n                en: \"Read scaling by adding read replicas\",\n                ro: \"Scalare citiri adăug\\xe2nd read replicas\"\n            },\n            {\n                en: \"Synchronous standby replica in another AZ for automatic failover\",\n                ro: \"Replică standby sincronă \\xeen alt AZ pentru failover automat\"\n            },\n            {\n                en: \"Cross-region disaster recovery\",\n                ro: \"Disaster recovery cross-region\"\n            },\n            {\n                en: \"Backup to S3 Glacier\",\n                ro: \"Backup \\xeen S3 Glacier\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Multi-AZ creates a synchronous standby replica in a different AZ. If the primary fails, RDS automatically fails over (typically <60s). This provides High Availability, NOT read scaling — for reads use Read Replicas.\",\n            ro: \"Multi-AZ creează o replică standby sincronă \\xeen alt AZ. La defect, RDS face failover automat (<60s). Oferă HA, NU scalare citiri — pentru citiri folosește Read Replicas.\"\n        },\n        relatedServices: [\n            \"rds\"\n        ]\n    },\n    // ========================================================================\n    // NETWORK\n    // ========================================================================\n    {\n        id: \"q-vpc-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"network\"\n        ],\n        question: {\n            en: \"What is the difference between a Security Group and a Network ACL (NACL)?\",\n            ro: \"Care e diferența dintre un Security Group și un Network ACL (NACL)?\"\n        },\n        options: [\n            {\n                en: \"Security Groups are stateless; NACLs are stateful\",\n                ro: \"Security Groups sunt stateless; NACL-urile sunt stateful\"\n            },\n            {\n                en: \"Security Groups operate at the instance level (stateful); NACLs at the subnet level (stateless)\",\n                ro: \"Security Groups la nivel instanță (stateful); NACL-uri la nivel subnet (stateless)\"\n            },\n            {\n                en: \"NACLs are global; Security Groups are regional\",\n                ro: \"NACL-urile sunt globale; Security Groups regionale\"\n            },\n            {\n                en: \"They are identical\",\n                ro: \"Sunt identice\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Security Groups are STATEFUL firewalls at the instance level (return traffic auto-allowed). NACLs are STATELESS firewalls at the subnet level (must explicitly allow inbound AND outbound). Security Groups can only ALLOW; NACLs can ALLOW or DENY.\",\n            ro: \"Security Groups sunt firewall-uri STATEFUL la nivel de instanță (traficul de retur permis automat). NACL-urile sunt STATELESS la nivel de subnet (trebuie să permiți explicit inbound ȘI outbound). Security Groups doar ALLOW; NACL-urile ALLOW sau DENY.\"\n        },\n        relatedServices: [\n            \"vpc\"\n        ]\n    },\n    {\n        id: \"q-route53-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"network\"\n        ],\n        question: {\n            en: \"A company wants to direct traffic to the AWS Region with the lowest latency for each user. Which Route 53 routing policy?\",\n            ro: \"O companie vrea să direcționeze traficul la Regiunea AWS cu latența cea mai mică pentru fiecare user. Ce politică de routing Route 53?\"\n        },\n        options: [\n            {\n                en: \"Simple\",\n                ro: \"Simple\"\n            },\n            {\n                en: \"Weighted\",\n                ro: \"Weighted\"\n            },\n            {\n                en: \"Latency-based\",\n                ro: \"Latency-based\"\n            },\n            {\n                en: \"Geolocation\",\n                ro: \"Geolocation\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Latency-based routing sends users to the AWS Region with the lowest measured latency. Geolocation routes by the user's country (not necessarily lowest latency). Weighted splits by percentage. Simple gives one endpoint.\",\n            ro: \"Latency-based trimite userii la Regiunea cu latența măsurată cea mai mică. Geolocation rutează după țara userului (nu neapărat latență minimă). Weighted face split procentual. Simple un endpoint.\"\n        },\n        relatedServices: [\n            \"route53\"\n        ]\n    },\n    // ========================================================================\n    // SECURITY / IAM\n    // ========================================================================\n    {\n        id: \"q-iam-root\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"security\"\n        ],\n        question: {\n            en: \"Which is a recommended best practice for the AWS root account?\",\n            ro: \"Care e best practice pentru contul root AWS?\"\n        },\n        options: [\n            {\n                en: \"Use it for daily administration tasks\",\n                ro: \"\\xcel folosești pentru administrare zilnică\"\n            },\n            {\n                en: \"Disable MFA to make access easier\",\n                ro: \"Dezactivezi MFA ca să accesezi ușor\"\n            },\n            {\n                en: \"Enable MFA and use only for specific tasks like account/billing changes\",\n                ro: \"Activezi MFA și \\xeel folosești doar pentru schimbări cont/facturare\"\n            },\n            {\n                en: \"Share the credentials with the entire team\",\n                ro: \"\\xcemparți credențialele cu toată echipa\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"The root account should have MFA enabled and be used only for specific tasks (initial setup, billing, account closure). For daily work, create IAM users/roles with least-privilege permissions.\",\n            ro: \"Contul root trebuie să aibă MFA activat și să fie folosit doar pentru sarcini specifice (setup inițial, facturare, \\xeenchidere cont). Pentru muncă zilnică, creezi useri/roluri IAM cu privilegii minime.\"\n        },\n        relatedServices: [\n            \"iam\"\n        ]\n    },\n    {\n        id: \"q-iam-role-ec2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        question: {\n            en: \"An EC2 instance needs to access an S3 bucket. What is the BEST way to grant permissions?\",\n            ro: \"O instanță EC2 trebuie să acceseze un bucket S3. Care e cel MAI bun mod de a da permisiuni?\"\n        },\n        options: [\n            {\n                en: \"Hardcode access keys in the application\",\n                ro: \"Hardcodezi access keys \\xeen aplicație\"\n            },\n            {\n                en: \"Store access keys in EC2 user data\",\n                ro: \"Stochezi access keys \\xeen EC2 user data\"\n            },\n            {\n                en: \"Attach an IAM Role to the EC2 instance\",\n                ro: \"Atașezi un IAM Role la instanța EC2\"\n            },\n            {\n                en: \"Make the S3 bucket public\",\n                ro: \"Faci bucket-ul S3 public\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Always use IAM Roles for AWS services (EC2, Lambda, ECS). The role provides temporary credentials that auto-rotate. NEVER hardcode access keys — they can be leaked in code, logs, or images.\",\n            ro: \"Folosește mereu IAM Roles pentru servicii AWS (EC2, Lambda, ECS). Rolul oferă credențiale temporare care se rotesc automat. NICIODATĂ hardcode access keys — pot fi leak-uite \\xeen cod, log-uri, imagini.\"\n        },\n        relatedServices: [\n            \"iam\",\n            \"ec2\",\n            \"s3\"\n        ]\n    },\n    {\n        id: \"q-kms-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        question: {\n            en: \"Which AWS service centrally manages encryption keys for services like S3, EBS, and RDS?\",\n            ro: \"Care serviciu AWS gestionează centralizat cheile de criptare pentru S3, EBS, RDS?\"\n        },\n        options: [\n            {\n                en: \"AWS Secrets Manager\",\n                ro: \"AWS Secrets Manager\"\n            },\n            {\n                en: \"AWS KMS\",\n                ro: \"AWS KMS\"\n            },\n            {\n                en: \"AWS Certificate Manager\",\n                ro: \"AWS Certificate Manager\"\n            },\n            {\n                en: \"AWS WAF\",\n                ro: \"AWS WAF\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"AWS KMS (Key Management Service) centrally manages encryption keys (CMKs). Used by S3, EBS, RDS, Secrets Manager. Every key usage is logged in CloudTrail. Secrets Manager stores secrets like passwords, not encryption keys themselves.\",\n            ro: \"AWS KMS (Key Management Service) gestionează centralizat cheile (CMKs). Folosit de S3, EBS, RDS, Secrets Manager. Fiecare utilizare e log-ată \\xeen CloudTrail. Secrets Manager stochează secrete (parole), nu cheile.\"\n        },\n        relatedServices: [\n            \"kms\",\n            \"s3\",\n            \"ebs\",\n            \"rds\"\n        ]\n    },\n    {\n        id: \"q-shield-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"security\"\n        ],\n        question: {\n            en: \"Which AWS service automatically protects ALL AWS resources from common DDoS attacks at no extra cost?\",\n            ro: \"Care serviciu AWS protejează automat TOATE resursele AWS de atacuri DDoS comune fără cost suplimentar?\"\n        },\n        options: [\n            {\n                en: \"AWS WAF\",\n                ro: \"AWS WAF\"\n            },\n            {\n                en: \"AWS Shield Standard\",\n                ro: \"AWS Shield Standard\"\n            },\n            {\n                en: \"AWS Shield Advanced\",\n                ro: \"AWS Shield Advanced\"\n            },\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"Shield Standard is FREE and automatic for all AWS customers — protects against common Layer 3/4 DDoS attacks. Shield Advanced costs $3,000/month and adds Layer 7 protection, 24/7 DDoS Response Team, cost protection. WAF protects against application-layer attacks (SQLi, XSS).\",\n            ro: \"Shield Standard e GRATUIT și automat pentru toți clienții AWS — protejează la atacuri DDoS comune Layer 3/4. Shield Advanced costă $3,000/lună și adaugă protecție Layer 7, DDoS Response Team 24/7, cost protection. WAF protejează la atacuri de aplicație (SQLi, XSS).\"\n        },\n        relatedServices: [\n            \"shield\",\n            \"waf\",\n            \"guardduty\"\n        ]\n    },\n    // ========================================================================\n    // PRICING & SUPPORT\n    // ========================================================================\n    {\n        id: \"q-pricing-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"billing\",\n            \"pricing\"\n        ],\n        question: {\n            en: \"Which of the following is FREE in AWS (i.e., no charge for the service itself)?\",\n            ro: \"Care din următoarele sunt GRATUITE \\xeen AWS (fără cost pentru serviciu)?\"\n        },\n        options: [\n            {\n                en: \"Amazon EC2\",\n                ro: \"Amazon EC2\"\n            },\n            {\n                en: \"AWS IAM\",\n                ro: \"AWS IAM\"\n            },\n            {\n                en: \"Amazon RDS\",\n                ro: \"Amazon RDS\"\n            },\n            {\n                en: \"Amazon Redshift\",\n                ro: \"Amazon Redshift\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"IAM is completely free. Other free services: VPC, CloudFormation, Auto Scaling, Elastic Beanstalk (you pay only for resources used). EC2, RDS, Redshift all have hourly costs.\",\n            ro: \"IAM e complet gratuit. Alte servicii gratuite: VPC, CloudFormation, Auto Scaling, Elastic Beanstalk (plătești doar resursele). EC2, RDS, Redshift au costuri orare.\"\n        },\n        relatedServices: [\n            \"iam\",\n            \"vpc\",\n            \"cloudformation\"\n        ]\n    },\n    {\n        id: \"q-pricing-2\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"billing\",\n            \"pricing\"\n        ],\n        question: {\n            en: 'Which AWS pricing principle reflects \"the more you use, the less you pay per unit\"?',\n            ro: 'Care principiu de preț AWS reflectă \"cu c\\xe2t folosești mai mult, plătești mai puțin per unitate\"?'\n        },\n        options: [\n            {\n                en: \"Pay-as-you-go\",\n                ro: \"Pay-as-you-go\"\n            },\n            {\n                en: \"Pay less when you reserve\",\n                ro: \"Plătești mai puțin rezerv\\xe2nd\"\n            },\n            {\n                en: \"Pay less per unit when you use more (volume tiered)\",\n                ro: \"Plătești mai puțin per unitate c\\xe2nd folosești mai mult (volum tiered)\"\n            },\n            {\n                en: \"Free tier\",\n                ro: \"Free tier\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"AWS uses tiered pricing for many services (S3, data transfer): the more you use, the cheaper the per-unit price. Pay-as-you-go is the basic principle (no commitment). Reserved is the discount-by-commitment one.\",\n            ro: \"AWS folosește tiered pricing pentru multe servicii (S3, transfer date): cu c\\xe2t folosești mai mult, costul per unitate scade. Pay-as-you-go e principiul de bază (fără angajament). Reserved e reducere prin angajament.\"\n        },\n        relatedServices: [\n            \"s3\"\n        ]\n    },\n    {\n        id: \"q-budgets-explorer\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"billing\",\n            \"management\"\n        ],\n        question: {\n            en: \"A finance team wants to receive an email alert when monthly AWS spending exceeds $10,000. Which service?\",\n            ro: \"O echipă de finanțe vrea să primească alertă email c\\xe2nd cheltuiala lunară AWS depășește $10,000. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"AWS Cost Explorer\",\n                ro: \"AWS Cost Explorer\"\n            },\n            {\n                en: \"AWS Budgets\",\n                ro: \"AWS Budgets\"\n            },\n            {\n                en: \"AWS Pricing Calculator\",\n                ro: \"AWS Pricing Calculator\"\n            },\n            {\n                en: \"AWS Trusted Advisor\",\n                ro: \"AWS Trusted Advisor\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"AWS Budgets sends proactive alerts (email/SNS) when costs exceed thresholds. Cost Explorer is for visualizing past costs. Pricing Calculator is for estimating future costs. Trusted Advisor gives optimization suggestions.\",\n            ro: \"AWS Budgets trimite alerte proactive (email/SNS) c\\xe2nd costurile depășesc praguri. Cost Explorer vizualizează costuri istorice. Pricing Calculator estimează costuri viitoare. Trusted Advisor dă sugestii de optimizare.\"\n        },\n        relatedServices: [\n            \"budgets\",\n            \"costexplorer\",\n            \"calculator\"\n        ]\n    },\n    {\n        id: \"q-support-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"support\"\n        ],\n        question: {\n            en: \"Which AWS Support plan is the LOWEST tier that includes a dedicated Technical Account Manager (TAM)?\",\n            ro: \"Care e cel mai mic plan AWS Support care include un Technical Account Manager (TAM) dedicat?\"\n        },\n        options: [\n            {\n                en: \"Developer\",\n                ro: \"Developer\"\n            },\n            {\n                en: \"Business\",\n                ro: \"Business\"\n            },\n            {\n                en: \"Enterprise On-Ramp\",\n                ro: \"Enterprise On-Ramp\"\n            },\n            {\n                en: \"Enterprise\",\n                ro: \"Enterprise\"\n            }\n        ],\n        correct: 3,\n        explanation: {\n            en: \"Only the Enterprise plan ($15,000/month) includes a dedicated TAM. Enterprise On-Ramp ($5,500/month) provides access to a POOL of TAMs, not a dedicated one. Business and below have no TAM.\",\n            ro: \"Doar planul Enterprise ($15,000/lună) include TAM dedicat. Enterprise On-Ramp ($5,500/lună) oferă acces la un POOL de TAM-uri, nu unul dedicat. Business și mai jos nu au TAM.\"\n        },\n        relatedServices: [\n            \"supportplans\"\n        ]\n    },\n    {\n        id: \"q-trustedadvisor-1\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"management\",\n            \"support\"\n        ],\n        question: {\n            en: \"Which service provides automated recommendations across cost, performance, security, fault tolerance, and service limits?\",\n            ro: \"Care serviciu oferă recomandări automate pentru cost, performanță, securitate, fault tolerance și service limits?\"\n        },\n        options: [\n            {\n                en: \"AWS Trusted Advisor\",\n                ro: \"AWS Trusted Advisor\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            },\n            {\n                en: \"AWS CloudTrail\",\n                ro: \"AWS CloudTrail\"\n            },\n            {\n                en: \"Amazon Inspector\",\n                ro: \"Amazon Inspector\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"Trusted Advisor is the automated AWS advisor with 5 pillars: Cost, Performance, Security, Fault Tolerance, Service Limits. Basic/Developer plans get 7 security checks; Business+ gets full checks.\",\n            ro: \"Trusted Advisor e consilierul automat AWS cu 5 piloni: Cost, Performance, Security, Fault Tolerance, Service Limits. Basic/Developer primesc 7 checks securitate; Business+ primește toate.\"\n        },\n        relatedServices: [\n            \"trustedadvisor\"\n        ]\n    },\n    // ========================================================================\n    // MANAGEMENT & MONITORING\n    // ========================================================================\n    {\n        id: \"q-cloudtrail-watch\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"management\"\n        ],\n        question: {\n            en: \"Which service records WHO made API calls in your AWS account, providing an audit log of activity?\",\n            ro: \"Care serviciu \\xeenregistrează CINE a făcut apeluri API \\xeen contul AWS, oferind audit log?\"\n        },\n        options: [\n            {\n                en: \"Amazon CloudWatch\",\n                ro: \"Amazon CloudWatch\"\n            },\n            {\n                en: \"AWS CloudTrail\",\n                ro: \"AWS CloudTrail\"\n            },\n            {\n                en: \"AWS Config\",\n                ro: \"AWS Config\"\n            },\n            {\n                en: \"Amazon GuardDuty\",\n                ro: \"Amazon GuardDuty\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudTrail logs every API call in your account (who, what, when, from where). CloudWatch is for metrics and logs from applications. Config tracks resource state changes (not API calls). GuardDuty does threat detection using CloudTrail/VPC logs.\",\n            ro: \"CloudTrail loghează fiecare apel API (cine, ce, c\\xe2nd, de unde). CloudWatch e pentru metrici și log-uri aplicații. Config urmărește schimbări de stare resurse (nu apeluri API). GuardDuty face detecție amenințări folosind CloudTrail/VPC logs.\"\n        },\n        relatedServices: [\n            \"cloudtrail\",\n            \"cloudwatch\",\n            \"config\"\n        ]\n    },\n    {\n        id: \"q-cloudformation-1\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"management\"\n        ],\n        question: {\n            en: \"Which AWS service provides Infrastructure as Code (IaC) using YAML/JSON templates?\",\n            ro: \"Care serviciu AWS oferă Infrastructure as Code (IaC) cu template-uri YAML/JSON?\"\n        },\n        options: [\n            {\n                en: \"AWS Systems Manager\",\n                ro: \"AWS Systems Manager\"\n            },\n            {\n                en: \"AWS CloudFormation\",\n                ro: \"AWS CloudFormation\"\n            },\n            {\n                en: \"AWS OpsWorks\",\n                ro: \"AWS OpsWorks\"\n            },\n            {\n                en: \"AWS Service Catalog\",\n                ro: \"AWS Service Catalog\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: \"CloudFormation lets you declare AWS resources in YAML/JSON templates and AWS provisions them atomically (with auto-rollback on failure). It IS the IaC service. Systems Manager is for fleet management. OpsWorks uses Chef/Puppet.\",\n            ro: \"CloudFormation \\xeeți permite să declari resurse AWS \\xeen template-uri YAML/JSON și AWS le provisiona atomic (cu rollback automat la eșec). E SERVICIUL IaC. Systems Manager e pentru fleet management. OpsWorks folosește Chef/Puppet.\"\n        },\n        relatedServices: [\n            \"cloudformation\",\n            \"systemsmanager\"\n        ]\n    },\n    // ========================================================================\n    // INTEGRATION\n    // ========================================================================\n    {\n        id: \"q-sqs-sns\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"integration\"\n        ],\n        question: {\n            en: \"A producer needs to send the SAME message to multiple subscribers (Lambda, email, SQS queue) at once. Which service?\",\n            ro: \"Un producător trebuie să trimită ACELAȘI mesaj la mai mulți subscribers (Lambda, email, coadă SQS) deodată. Ce serviciu?\"\n        },\n        options: [\n            {\n                en: \"Amazon SQS\",\n                ro: \"Amazon SQS\"\n            },\n            {\n                en: \"Amazon SNS\",\n                ro: \"Amazon SNS\"\n            },\n            {\n                en: \"Amazon Kinesis\",\n                ro: \"Amazon Kinesis\"\n            },\n            {\n                en: \"AWS Step Functions\",\n                ro: \"AWS Step Functions\"\n            }\n        ],\n        correct: 1,\n        explanation: {\n            en: 'SNS is pub/sub: one Topic delivers to many Subscribers (Lambda, email, SMS, SQS, HTTP). SQS is point-to-point queuing (one message, one consumer). The \"fan-out\" pattern uses SNS → multiple SQS queues.',\n            ro: 'SNS e pub/sub: un Topic livrează la mulți Subscribers (Lambda, email, SMS, SQS, HTTP). SQS e queue point-to-point (un mesaj, un consumer). Pattern-ul \"fan-out\" folosește SNS → mai multe SQS.'\n        },\n        relatedServices: [\n            \"sns\",\n            \"sqs\"\n        ]\n    },\n    // ========================================================================\n    // WELL-ARCHITECTED\n    // ========================================================================\n    {\n        id: \"q-wa-pillars\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"well-architected\"\n        ],\n        question: {\n            en: \"How many pillars does the AWS Well-Architected Framework have?\",\n            ro: \"C\\xe2ți piloni are AWS Well-Architected Framework?\"\n        },\n        options: [\n            {\n                en: \"4\",\n                ro: \"4\"\n            },\n            {\n                en: \"5\",\n                ro: \"5\"\n            },\n            {\n                en: \"6\",\n                ro: \"6\"\n            },\n            {\n                en: \"7\",\n                ro: \"7\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Six pillars: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization, and Sustainability (added in late 2021).\",\n            ro: \"Șase piloni: Operational Excellence, Security, Reliability, Performance Efficiency, Cost Optimization și Sustainability (adăugat \\xeen 2021).\"\n        },\n        relatedServices: []\n    },\n    {\n        id: \"q-wa-reliability\",\n        type: \"multiple_choice\",\n        difficulty: 2,\n        categories: [\n            \"well-architected\"\n        ],\n        question: {\n            en: \"Deploying an application across multiple Availability Zones with Auto Scaling primarily addresses which Well-Architected pillar?\",\n            ro: \"Deploy-ul unei aplicații peste mai multe AZ-uri cu Auto Scaling adresează \\xeen principal care pilon Well-Architected?\"\n        },\n        options: [\n            {\n                en: \"Cost Optimization\",\n                ro: \"Cost Optimization\"\n            },\n            {\n                en: \"Operational Excellence\",\n                ro: \"Operational Excellence\"\n            },\n            {\n                en: \"Reliability\",\n                ro: \"Reliability\"\n            },\n            {\n                en: \"Sustainability\",\n                ro: \"Sustainability\"\n            }\n        ],\n        correct: 2,\n        explanation: {\n            en: \"Multi-AZ + Auto Scaling = Reliability pillar (recover from failure, automatically scale to meet demand). It also touches Performance Efficiency, but the primary goal is fault tolerance / availability.\",\n            ro: \"Multi-AZ + Auto Scaling = pilonul Reliability (recovery la defect, scalare automată la cerere). Atinge și Performance Efficiency, dar scopul principal e fault tolerance / availability.\"\n        },\n        relatedServices: [\n            \"ec2\",\n            \"elb\"\n        ]\n    },\n    // ========================================================================\n    // CLOUD FUNDAMENTALS\n    // ========================================================================\n    {\n        id: \"q-cloud-capex\",\n        type: \"multiple_choice\",\n        difficulty: 1,\n        categories: [\n            \"cloud-fundamentals\"\n        ],\n        question: {\n            en: 'Moving to AWS allows organizations to \"trade CAPEX for OPEX\". What does this mean?',\n            ro: 'Mutarea la AWS permite organizațiilor să \"schimbe CAPEX cu OPEX\". Ce \\xeenseamnă asta?'\n        },\n        options: [\n            {\n                en: \"Replace upfront capital expenses with variable operational expenses\",\n                ro: \"\\xcenlocuiești cheltuielile capitale upfront cu operaționale variabile\"\n            },\n            {\n                en: \"Pay more upfront for cheaper monthly bills\",\n                ro: \"Plătești mai mult upfront pentru facturi lunare mai mici\"\n            },\n            {\n                en: \"Eliminate all costs\",\n                ro: \"Elimini toate costurile\"\n            },\n            {\n                en: \"Move all servers on-premises\",\n                ro: \"Muți toate serverele on-premises\"\n            }\n        ],\n        correct: 0,\n        explanation: {\n            en: \"CAPEX (Capital Expenditure) = large upfront investments in hardware. OPEX (Operational Expenditure) = pay-as-you-go cloud costs. Trading CAPEX for OPEX means no big purchases — you pay only for what you use.\",\n            ro: \"CAPEX (Capital Expenditure) = investiții upfront mari \\xeen hardware. OPEX (Operational Expenditure) = costuri pay-as-you-go cloud. Schimbarea CAPEX→OPEX \\xeenseamnă fără achiziții mari — plătești doar ce folosești.\"\n        },\n        relatedServices: []\n    }\n];\n/**\n * Heuristic to map legacy questions (no `examDomain` field) to a domain\n * based on their existing `categories` tags. Keeps backwards-compat without\n * editing the 30 v0.2 questions.\n */ function inferDomain(q) {\n    if (q.examDomain) return q.examDomain;\n    const cats = q.categories;\n    if (cats.some((c)=>[\n            \"security\",\n            \"compliance\"\n        ].includes(c))) return \"security\";\n    if (cats.some((c)=>[\n            \"billing\",\n            \"pricing\",\n            \"support\"\n        ].includes(c))) return \"billing-support\";\n    if (cats.some((c)=>[\n            \"cloud-fundamentals\",\n            \"well-architected\",\n            \"caf\",\n            \"global-infrastructure\"\n        ].includes(c))) return \"cloud-concepts\";\n    return \"tech-services\";\n}\n/**\n * The full quiz bank: 30 legacy + ~67 domain-tagged questions = ~97 total.\n * Every question gets a guaranteed `examDomain` (inferred for legacy ones).\n */ const quizQuestions = [\n    ...legacyQuestions,\n    ..._questions_cloud_concepts__WEBPACK_IMPORTED_MODULE_0__.cloudConceptsQuestions,\n    ..._questions_security__WEBPACK_IMPORTED_MODULE_1__.securityQuestions,\n    ..._questions_tech_services__WEBPACK_IMPORTED_MODULE_2__.techServicesQuestions,\n    ..._questions_billing_support__WEBPACK_IMPORTED_MODULE_3__.billingSupportQuestions,\n    ..._questions_extra__WEBPACK_IMPORTED_MODULE_4__.extraQuestions\n].map((q)=>({\n        ...q,\n        examDomain: inferDomain(q)\n    }));\n/**\n * Official CLF-C02 domain weights (percentages of the 65-question exam).\n * Used to build a properly-weighted Practice Exam.\n */ const DOMAIN_WEIGHTS = {\n    \"cloud-concepts\": 0.24,\n    security: 0.30,\n    \"tech-services\": 0.34,\n    \"billing-support\": 0.12\n};\nfunction getQuestionsByCategory(categoryIds) {\n    return quizQuestions.filter((q)=>q.categories.some((c)=>categoryIds.includes(c)));\n}\nfunction getQuestionsByDomain(domain) {\n    return quizQuestions.filter((q)=>q.examDomain === domain);\n}\nfunction getRandomQuestions(count) {\n    const shuffled = [\n        ...quizQuestions\n    ].sort(()=>Math.random() - 0.5);\n    return shuffled.slice(0, count);\n}\n/**\n * Build a domain-weighted random sample (e.g., for the 65-question Practice Exam).\n * Picks ceil(weight * total) per domain, shuffles the union, trims to `total`.\n */ function buildWeightedExam(total = 65) {\n    const out = [];\n    Object.keys(DOMAIN_WEIGHTS).forEach((d)=>{\n        const target = Math.ceil(DOMAIN_WEIGHTS[d] * total);\n        const pool = getQuestionsByDomain(d);\n        const shuffled = [\n            ...pool\n        ].sort(()=>Math.random() - 0.5);\n        out.push(...shuffled.slice(0, Math.min(target, shuffled.length)));\n    });\n    // Final shuffle so domains don't appear in clusters\n    return out.sort(()=>Math.random() - 0.5).slice(0, total);\n}\n/**\n * Smart sampler: prefers questions NOT in the user's recently-seen ring buffer\n * so consecutive sessions feel fresh. Falls back to seen questions if the\n * fresh pool is too small.\n */ function buildQuiz(count, scope = \"all\", recentlySeen = []) {\n    // 1. filter by scope\n    let pool;\n    if (scope === \"all\") {\n        pool = quizQuestions;\n    } else if (scope.startsWith(\"category:\")) {\n        const cat = scope.slice(\"category:\".length);\n        pool = quizQuestions.filter((q)=>q.categories.includes(cat));\n    } else {\n        pool = getQuestionsByDomain(scope);\n    }\n    if (pool.length === 0) return [];\n    // 2. Split into \"fresh\" (not recently seen) and \"stale\" (seen)\n    const seenSet = new Set(recentlySeen);\n    const fresh = pool.filter((q)=>!seenSet.has(q.id));\n    const stale = pool.filter((q)=>seenSet.has(q.id));\n    // 3. Shuffle each, then concat (fresh first) and take `count`\n    const shuf = (arr)=>[\n            ...arr\n        ].sort(()=>Math.random() - 0.5);\n    const ordered = [\n        ...shuf(fresh),\n        ...shuf(stale)\n    ];\n    return ordered.slice(0, Math.min(count, ordered.length));\n}\n/**\n * For the home Daily Challenge: deterministic-ish random based on date,\n * so all visits today see the same 5 questions. Different each day.\n */ function getDailyChallengeQuestions(date, count = 5) {\n    // Cheap hash of the date string → seed\n    let seed = 0;\n    for(let i = 0; i < date.length; i++)seed = seed * 31 + date.charCodeAt(i) >>> 0;\n    // Mulberry32 PRNG seeded with the date\n    const rand = ()=>{\n        seed = seed + 0x6d2b79f5 >>> 0;\n        let t = seed;\n        t = Math.imul(t ^ t >>> 15, t | 1);\n        t ^= t + Math.imul(t ^ t >>> 7, t | 61);\n        return ((t ^ t >>> 14) >>> 0) / 4294967296;\n    };\n    const pool = [\n        ...quizQuestions\n    ];\n    // Fisher-Yates with seeded rand\n    for(let i = pool.length - 1; i > 0; i--){\n        const j = Math.floor(rand() * (i + 1));\n        [pool[i], pool[j]] = [\n            pool[j],\n            pool[i]\n        ];\n    }\n    return pool.slice(0, count);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/quiz-questions.ts\n");

